/// Format the current wall-clock time as "YYYY-MM-DD HH:MM:SS UTC" for RPL_TIME.
fn formatServerTime(buf: []u8) []const u8 {
    const ms = platform.realtimeMillis();
    const secs: u64 = @intCast(@divTrunc(ms, 1000));
    const es = std.time.epoch.EpochSeconds{ .secs = secs };
    const yd = es.getEpochDay().calculateYearDay();
    const md = yd.calculateMonthDay();
    const ds = es.getDaySeconds();
    return std.fmt.bufPrint(buf, "{d:0>4}-{d:0>2}-{d:0>2} {d:0>2}:{d:0>2}:{d:0>2} UTC", .{
        yd.year,              md.month.numeric(),      @as(u16, md.day_index) + 1,
        ds.getHoursIntoDay(), ds.getMinutesIntoHour(), ds.getSecondsIntoMinute(),
    }) catch "unknown";
}

/// IRCv3 server-time tag: `@time=2026-06-04T12:34:56.789Z ` (ISO-8601 UTC with
/// millisecond precision, trailing space so it prepends directly before the ':'
/// message prefix). Empty string on format failure (tag simply omitted).
fn serverTimeTag(buf: []u8) []const u8 {
    const ms = platform.realtimeMillis();
    const secs: u64 = @intCast(@divTrunc(ms, 1000));
    const millis: u16 = @intCast(@mod(ms, 1000));
    const es = std.time.epoch.EpochSeconds{ .secs = secs };
    const yd = es.getEpochDay().calculateYearDay();
    const md = yd.calculateMonthDay();
    const ds = es.getDaySeconds();
    return std.fmt.bufPrint(buf, "@time={d:0>4}-{d:0>2}-{d:0>2}T{d:0>2}:{d:0>2}:{d:0>2}.{d:0>3}Z ", .{
        yd.year,              md.month.numeric(),      @as(u16, md.day_index) + 1,
        ds.getHoursIntoDay(), ds.getMinutesIntoHour(), ds.getSecondsIntoMinute(),
        millis,
    }) catch "";
}

/// The bare ISO-8601 server-time VALUE (no `@time=` key, no trailing space) for
/// composing a multi-tag segment via buildTagPrefix.
fn serverTimeValue(buf: []u8) []const u8 {
    const ms = platform.realtimeMillis();
    const secs: u64 = @intCast(@divTrunc(ms, 1000));
    const millis: u16 = @intCast(@mod(ms, 1000));
    const es = std.time.epoch.EpochSeconds{ .secs = secs };
    const yd = es.getEpochDay().calculateYearDay();
    const md = yd.calculateMonthDay();
    const ds = es.getDaySeconds();
    return std.fmt.bufPrint(buf, "{d:0>4}-{d:0>2}-{d:0>2}T{d:0>2}:{d:0>2}:{d:0>2}.{d:0>3}Z", .{
        yd.year,              md.month.numeric(),      @as(u16, md.day_index) + 1,
        ds.getHoursIntoDay(), ds.getMinutesIntoHour(), ds.getSecondsIntoMinute(),
        millis,
    }) catch "";
}

/// Assemble a per-recipient IRCv3 tag segment `@k=v;k=v ` (trailing space) from
/// the tags available this event and the caps `session` negotiated. Returns ""
/// when the recipient gets no tags. Only ONE `@`-segment is ever emitted, so
/// server-time and account-tag coexist correctly (never two `@` blocks).
fn buildTagPrefix(session: *const dispatch.ClientSession, tags: LinuxServer.MsgTags, out: []u8) []const u8 {
    var b = Buf{ .storage = out };
    var any = false;
    if (tags.time_value.len != 0 and session.hasCap(.server_time)) {
        b.append("@time=") catch return "";
        b.append(tags.time_value) catch return "";
        any = true;
    }
    if (session.hasCap(.account_tag)) {
        if (tags.account) |acct| {
            b.append(if (any) ";account=" else "@account=") catch return "";
            b.append(acct) catch return "";
            any = true;
        }
    }
    // msgid: the server-minted per-message id, delivered to recipients that
    // negotiated message-tags (the prerequisite for receiving server tags).
    // This is what message-redaction later references.
    if (tags.msgid) |id| {
        if (session.hasCap(.message_tags)) {
            b.append(if (any) ";msgid=" else "@msgid=") catch return "";
            b.append(id) catch return "";
            any = true;
        }
    }
    if (tags.is_bot and session.hasCap(.message_tags)) {
        b.append(if (any) ";bot" else "@bot") catch return "";
        any = true;
    }
    // Relay the sender's CLIENT-ONLY (`+`) tags to message-tags recipients,
    // merged into the single @-segment. Server-supplied tags in the sender's
    // segment (no `+`) are NOT relayed, so a client can't spoof server-time etc.
    if (tags.client_tags) |raw| {
        var filtered_buf: [irc_line.max_client_tags_raw_len]u8 = undefined;
        const filtered = clientTagsForSession(session, raw, &filtered_buf);
        if (filtered.len != 0) {
            var it = std.mem.splitScalar(u8, filtered, ';');
            while (it.next()) |t| {
                if (t.len == 0 or t[0] != '+') continue;
                b.append(if (any) ";" else "@") catch return "";
                b.append(t) catch return "";
                any = true;
            }
        }
    }
    if (!any) return "";
    b.appendByte(' ') catch return "";
    return b.written();
}

/// ISON predicate: nicks are pre-filtered to online before the builder runs.
fn alwaysOnline(_: []const u8) bool {
    return true;
}

/// The value of the IRCv3 `batch` tag on a line, or null if absent. Parses the
/// raw tag segment (the daemon's line parser keeps tags as `tags_raw`).
fn batchTagValue(parsed: *const irc_line.LineView) ?[]const u8 {
    const raw = parsed.tags_raw orelse return null;
    var it = std.mem.splitScalar(u8, raw, ';');
    while (it.next()) |tag| {
        if (std.mem.startsWith(u8, tag, "batch=")) return tag["batch=".len..];
    }
    return null;
}

/// Whether a BATCH line opens a `draft/multiline` batch
/// (`BATCH +<ref> draft/multiline <target>`).
fn isMultilineOpen(parsed: *const irc_line.LineView) bool {
    return parsed.param_count == 3 and
        parsed.params[0].len >= 1 and parsed.params[0][0] == '+' and
        std.mem.eql(u8, parsed.params[1], multiline.draft_multiline_batch);
}

// The IRC version token (RPL_MYINFO 004 / RPL_VERSION 351 / INFO) carries the
// release semver plus the build's git commit ("orochi-0.1.0+8fba2c5") so
// `/version` shows the release AND traces back to the exact source revision.
const server_version = "orochi-" ++ build_info.version;
/// Personalized default MOTD, expanded per connection by `motd_template`
/// (operators override the whole thing via `[motd] text`). Conditional blocks
/// begin right after the prior line so an inactive branch leaves no blank line.
const default_motd_template =
    "{greeting}, {nick}! Welcome to {network}.\n" ++
    "You're on {server} ({version}) - {users} users online right now.{if:weather}\n" ++
    "Weather - {weather}.{/if}{if:news}\n" ++
    "Headlines - {news}.{/if}{if:account}\n" ++
    "Signed in as {account}; your services and saved settings are active.{else}\n" ++
    "Tip: register your account to reserve your nick and unlock services.{/if}{if:oper}\n" ++
    "Operator privileges are active on this connection - wield them with care.{/if}{if:secure}{else}\n" ++
    "Note: this link is not encrypted - reconnect over TLS for privacy.{/if}\n" ++
    "Orochi - a clean-room, Zig-native IRCX/IRCv3 daemon: Suimyaku CRDT mesh, forward-secret Tsumugi links.";

/// Reserved pseudo-channel used to gossip per-user PRESENCE across the mesh.
///
/// Channel membership is the only mesh-wide nick replication, so a remote user in
/// no real channel was previously unroutable for cross-node DMs. Every registered
/// local user is also announced as a member of this pseudo-channel (on register, in
/// the anti-entropy burst, and withdrawn on quit), which lands them in each peer's
/// route_table `nick_to_node` index exactly like a real membership — so the PRIVMSG
/// relay can resolve them.
///
/// The name is route-only and never surfaces to users: it leads with `~`, which no
/// channel-name validator accepts (`world.isChannelName` only takes `#`/`&`/`%`;
/// `svc_forceaction.isChannelName` adds `+`/`!`), so it can't be JOINed/NAMEd/LISTed
/// and is never created as a `world` channel; `drainMembershipChanges` also skips it
/// so no fabricated JOIN/PART leaks. It must stay printable & space-free: the
/// MEMBERSHIP codec (`membership_event.decode`) rejects control bytes (<0x20) in the
/// channel field, so a control-char sentinel would be silently dropped on receive.
/// See [[reference-orochi-crossnode-routing]].
const presence_channel: []const u8 = "~presence~";

inline fn isPresenceChannel(name: []const u8) bool {
    return std.mem.eql(u8, name, presence_channel);
}

/// Sink adapter that writes complete (CRLF-terminated) builder lines to a conn.
const ConnLineSink = struct {
    conn: *ConnState,
    // Narrow error set so it coerces into builder error sets (e.g. LusersError).
    pub fn send(self: *ConnLineSink, bytes: []const u8) error{OutputTooSmall}!void {
        appendToConn(self.conn, bytes) catch return error.OutputTooSmall;
    }
};

/// Like ConnLineSink but appends CRLF (for builders whose lines omit it, e.g. LIST).
const ConnLineSinkCRLF = struct {
    conn: *ConnState,
    pub fn send(self: *ConnLineSinkCRLF, bytes: []const u8) error{OutputTooSmall}!void {
        appendToConn(self.conn, bytes) catch return error.OutputTooSmall;
        appendToConn(self.conn, "\r\n") catch return error.OutputTooSmall;
    }
};

/// ASCII case-insensitive `[]const u8`-keyed hash context, matching the world's
/// channel casemapping so mesh-wide LIST/LISTX deduplication treats "#Room" and
/// "#room" as one channel.
const CiNameContext = struct {
    pub fn hash(_: CiNameContext, key: []const u8) u64 {
        var h = std.hash.Wyhash.init(0);
        for (key) |c| {
            const lc = std.ascii.toLower(c);
            h.update(std.mem.asBytes(&lc));
        }
        return h.final();
    }
    pub fn eql(_: CiNameContext, a: []const u8, b: []const u8) bool {
        return std.ascii.eqlIgnoreCase(a, b);
    }
};

/// Case-insensitive channel-name set used to deduplicate the mesh-wide channel
/// union in LIST/LISTX. Keys are borrowed from world/peer state, valid for the
/// enumerating handler turn.
const CiNameSet = std.HashMap([]const u8, void, CiNameContext, std.hash_map.default_max_load_percentage);

const irc_line = struct {
    pub const MAXPARA: usize = 15;
    pub const MAX_LINE_BODY: usize = 8191;

    pub const ParseError = error{
        EmptyLine,
        OversizeLine,
        EmbeddedNul,
        EmbeddedLineBreak,
        MissingCommand,
        MalformedPrefix,
        MalformedTags,
        TooManyParams,
    };

    pub const max_client_tags_raw_len: usize = 4094;
    pub const max_client_tag_count: usize = 32;
    const max_client_tag_key_len: usize = 96;

    pub const LineView = struct {
        raw: []const u8,
        prefix: ?[]const u8 = null,
        /// IRCv3 client message-tags segment WITHOUT the leading '@' (null if
        /// none). Relayed verbatim by TAGMSG to message-tags recipients.
        tags_raw: ?[]const u8 = null,
        command: []const u8,
        params: [MAXPARA][]const u8 = @splat(""),
        param_count: usize = 0,

        pub fn paramSlice(self: *const LineView) []const []const u8 {
            return self.params[0..self.param_count];
        }
    };

    pub fn parseLine(input: []const u8) ParseError!LineView {
        const body = stripLineEnding(input);
        if (body.len == 0) return error.EmptyLine;
        if (body.len > MAX_LINE_BODY) return error.OversizeLine;

        for (body) |ch| switch (ch) {
            0 => return error.EmbeddedNul,
            '\r', '\n' => return error.EmbeddedLineBreak,
            else => {},
        };

        var view = LineView{ .raw = body, .command = "" };
        var cursor = skipSpaces(body, 0);
        if (cursor >= body.len) return error.MissingCommand;

        if (body[cursor] == '@') {
            const tag_end = findSpace(body, cursor) orelse return error.MissingCommand;
            if (tag_end > cursor + 1) {
                const tags = body[cursor + 1 .. tag_end];
                try validateTagSegment(tags);
                view.tags_raw = tags;
            }
            cursor = skipSpaces(body, tag_end);
            if (cursor >= body.len) return error.MissingCommand;
        }

        if (body[cursor] == ':') {
            const prefix_end = findSpace(body, cursor) orelse return error.MissingCommand;
            if (prefix_end == cursor + 1) return error.MalformedPrefix;
            view.prefix = body[cursor + 1 .. prefix_end];
            cursor = skipSpaces(body, prefix_end);
            if (cursor >= body.len) return error.MissingCommand;
        }

        const command_end = findSpace(body, cursor) orelse body.len;
        if (command_end == cursor) return error.MissingCommand;
        view.command = body[cursor..command_end];
        cursor = skipSpaces(body, command_end);

        while (cursor < body.len) {
            if (view.param_count == MAXPARA) return error.TooManyParams;
            if (body[cursor] == ':') {
                view.params[view.param_count] = body[cursor + 1 ..];
                view.param_count += 1;
                break;
            }
            const end = findSpace(body, cursor) orelse body.len;
            view.params[view.param_count] = body[cursor..end];
            view.param_count += 1;
            cursor = skipSpaces(body, end);
        }

        return view;
    }

    fn validateTagSegment(raw: []const u8) ParseError!void {
        if (raw.len > max_client_tags_raw_len) return error.MalformedTags;

        var count: usize = 0;
        var it = std.mem.splitScalar(u8, raw, ';');
        while (it.next()) |tag| {
            if (tag.len == 0) return error.MalformedTags;
            count += 1;
            if (count > max_client_tag_count) return error.MalformedTags;

            const eq = std.mem.indexOfScalar(u8, tag, '=') orelse tag.len;
            const key = tag[0..eq];
            if (!validTagKey(key)) return error.MalformedTags;

            if (eq < tag.len) {
                for (tag[eq + 1 ..]) |ch| {
                    switch (ch) {
                        0, '\r', '\n', ' ', ';' => return error.MalformedTags,
                        else => {},
                    }
                }
            }
        }
    }

    fn validTagKey(key: []const u8) bool {
        if (key.len == 0 or key.len > max_client_tag_key_len) return false;
        const start: usize = if (key[0] == '+') 1 else 0;
        if (start == key.len) return false;
        for (key[start..]) |ch| {
            switch (ch) {
                'A'...'Z', 'a'...'z', '0'...'9', '-', '.', '/' => {},
                else => return false,
            }
        }
        return true;
    }

    fn stripLineEnding(input: []const u8) []const u8 {
        if (input.len >= 2 and input[input.len - 2] == '\r' and input[input.len - 1] == '\n') {
            return input[0 .. input.len - 2];
        }
        if (input.len >= 1 and (input[input.len - 1] == '\r' or input[input.len - 1] == '\n')) {
            return input[0 .. input.len - 1];
        }
        return input;
    }

    fn skipSpaces(bytes: []const u8, start: usize) usize {
        var cursor = start;
        while (cursor < bytes.len and bytes[cursor] == ' ') {
            cursor += 1;
        }
        return cursor;
    }

    fn findSpace(bytes: []const u8, start: usize) ?usize {
        var cursor = start;
        while (cursor < bytes.len) : (cursor += 1) {
            if (bytes[cursor] == ' ') return cursor;
        }
        return null;
    }
};

/// Public alias of the daemon's parsed-line view so module files (module_core.zig)
/// can name the type the live dispatch path uses.
pub const ParsedLine = irc_line.LineView;

/// Public alias of the daemon's numeric-reply code enum so modules can emit
/// numerics through `Core.reply` without reaching into server internals.
pub const ReplyCode = Numeric;

const ringlane = struct {
    const IoUring = linux.IoUring;

    pub const default_cqe_batch: usize = 256;
    pub const max_cqe_batch: usize = 4096;

    pub const RingFeatures = struct {
        multishot_accept: bool = false,
        multishot_recv: bool = false,
        buf_ring: bool = false,
        send_zc: bool = false,
        fixed_files: bool = false,
        defer_taskrun: bool = false,
        sqpoll: bool = false,

        pub const baseline: @This() = .{};

        fn setupFlags(self: @This()) u32 {
            var flags: u32 = 0;
            if (self.sqpoll) flags |= linux.IORING_SETUP_SQPOLL;
            if (self.defer_taskrun) {
                flags |= linux.IORING_SETUP_DEFER_TASKRUN;
                flags |= linux.IORING_SETUP_SINGLE_ISSUER;
            }
            return flags;
        }
    };

    pub const OpKind = enum(u8) {
        other = 0,
        accept = 1,
        recv = 2,
        send = 3,
        timeout = 4,
        connect = 5,
        // poll: readiness watch on a bare fd (e.g. a reactor's cross-reactor
        // wake eventfd). Fires a `.poll` completion when the fd is readable.
        poll = 6,
    };

    pub const FdToken = struct {
        slot: u32,
        gen: u32,
    };

    const gen_bits = 28;
    const slot_bits = 28;
    const slot_shift = gen_bits;
    const kind_shift = gen_bits + slot_bits;
    const field_mask: u64 = (1 << gen_bits) - 1;
    const slot_max: u32 = (1 << slot_bits) - 1;
    const gen_max: u32 = (1 << gen_bits) - 1;

    fn encodeUserData(kind: OpKind, token: FdToken) error{TokenOutOfRange}!u64 {
        if (token.slot > slot_max or token.gen > gen_max) return error.TokenOutOfRange;
        return (@as(u64, @intFromEnum(kind)) << kind_shift) |
            (@as(u64, token.slot) << slot_shift) |
            @as(u64, token.gen);
    }

    fn decodeUserData(raw: u64) error{UnknownOpKind}!struct { kind: OpKind, token: FdToken } {
        const kind_raw: u8 = @intCast(raw >> kind_shift);
        const kind: OpKind = switch (kind_raw) {
            0 => .other,
            1 => .accept,
            2 => .recv,
            3 => .send,
            4 => .timeout,
            5 => .connect,
            6 => .poll,
            else => return error.UnknownOpKind,
        };
        return .{
            .kind = kind,
            .token = .{
                .slot = @intCast((raw >> slot_shift) & field_mask),
                .gen = @intCast(raw & field_mask),
            },
        };
    }

    pub const AcceptEvent = struct {
        token: FdToken,
        res: i32,
        more: bool,
    };

    pub const RecvEvent = struct {
        token: FdToken,
        res: i32,
        more: bool,
    };

    pub const SendEvent = struct {
        token: FdToken,
        res: i32,
        more: bool,
        notif: bool,
    };

    pub const ConnectEvent = struct {
        token: FdToken,
        res: i32,
    };

    pub const PollEvent = struct {
        token: FdToken,
        res: i32,
    };

    pub const Completion = union(OpKind) {
        other: void,
        accept: AcceptEvent,
        recv: RecvEvent,
        send: SendEvent,
        timeout: void,
        connect: ConnectEvent,
        poll: PollEvent,
    };

    fn decodeCompletion(cqe: linux.io_uring_cqe) error{UnknownOpKind}!Completion {
        const ud = try decodeUserData(cqe.user_data);
        const more = (cqe.flags & linux.IORING_CQE_F_MORE) != 0;
        return switch (ud.kind) {
            .other => .{ .other = {} },
            .accept => .{ .accept = .{ .token = ud.token, .res = cqe.res, .more = more } },
            .recv => .{ .recv = .{ .token = ud.token, .res = cqe.res, .more = more } },
            .send => .{ .send = .{
                .token = ud.token,
                .res = cqe.res,
                .more = more,
                .notif = (cqe.flags & linux.IORING_CQE_F_NOTIF) != 0,
            } },
            .timeout => .{ .timeout = {} },
            .connect => .{ .connect = .{ .token = ud.token, .res = cqe.res } },
            .poll => .{ .poll = .{ .token = ud.token, .res = cqe.res } },
        };
    }

    pub fn isUnsupportedInitError(err: anyerror) bool {
        return switch (err) {
            error.PermissionDenied,
            error.SystemOutdated,
            error.SystemResources,
            error.ProcessFdQuotaExceeded,
            error.SystemFdQuotaExceeded,
            error.ArgumentsInvalid,
            => true,
            else => false,
        };
    }

    pub const Ring = struct {
        inner: IoUring,
        features: RingFeatures,

        pub fn init(entries: u16, features: RingFeatures) !Ring {
            return .{ .inner = try IoUring.init(entries, features.setupFlags()), .features = features };
        }

        pub fn deinit(self: *Ring) void {
            self.inner.deinit();
        }

        pub fn submit(self: *Ring) !u32 {
            return self.inner.submit();
        }

        pub fn submitAndWait(self: *Ring, wait_nr: u32) !u32 {
            return self.inner.submit_and_wait(wait_nr);
        }

        pub fn submitAccept(self: *Ring, token: FdToken, listener_fd: linux.fd_t) !void {
            _ = self.features;
            // Accept with SOCK_CLOEXEC so every accepted socket defaults to
            // close-on-exec. Helix UPGRADE re-execs the daemon in place; the
            // design (see performUpgrade) carries select client sockets by
            // explicitly CLEARING CLOEXEC on them, and relies on every other
            // accepted socket — S2S mesh peers, the requesting oper, wss
            // browser clients, TLS clients whose engine can't be exported —
            // closing at execve so the far end sees the drop and reconnects.
            // Without this flag those sockets leak across execve as orphans:
            // a re-exec'd meshed node strands its peer link (the peer keeps a
            // zombie ESTAB socket and dedups away every re-dial → split-brain).
            _ = try self.inner.accept(try encodeUserData(.accept, token), listener_fd, null, null, posix.SOCK.CLOEXEC);
        }

        pub fn submitRecv(self: *Ring, token: FdToken, fd: linux.fd_t, buffer: []u8) !void {
            _ = try self.inner.recv(try encodeUserData(.recv, token), fd, .{ .buffer = buffer }, 0);
        }

        pub fn submitConnect(self: *Ring, token: FdToken, fd: linux.fd_t, addr: *const posix.sockaddr, addrlen: posix.socklen_t) !void {
            _ = try self.inner.connect(try encodeUserData(.connect, token), fd, addr, addrlen);
        }

        pub fn submitSend(self: *Ring, token: FdToken, fd: linux.fd_t, buffer: []const u8) !void {
            _ = try self.inner.send(try encodeUserData(.send, token), fd, buffer, 0);
        }

        /// Queue a relative single-shot timeout; fires as a `.timeout` completion.
        pub fn submitTimeout(self: *Ring, token: FdToken, ts: *const linux.kernel_timespec) !void {
            _ = try self.inner.timeout(try encodeUserData(.timeout, token), ts, 0, 0);
        }

        /// Watch `fd` for readability (single-shot); fires a `.poll` completion.
        /// Used by a reactor to wake on its cross-reactor eventfd (see
        /// reactor_wake.zig) — re-arm after each completion.
        pub fn submitPollAdd(self: *Ring, token: FdToken, fd: linux.fd_t, poll_mask: u32) !void {
            _ = try self.inner.poll_add(try encodeUserData(.poll, token), fd, poll_mask);
        }

        pub fn reapCompletions(self: *Ring, out: []linux.io_uring_cqe, wait_nr: u32, handler: anytype) !void {
            const n = try self.inner.copy_cqes(out, wait_nr);
            for (out[0..n]) |cqe| {
                const completion = decodeCompletion(cqe) catch continue;
                handler.onCompletion(completion);
            }
        }
    };
};

const RingFdToken = ringlane.FdToken;
const RingCore = ringlane.Ring;
const RingFeatureSet = ringlane.RingFeatures;

const listener_token: RingFdToken = .{ .slot = 0, .gen = 0 };
/// Distinct accept token for the S2S listener so handleAccept can tell the two
/// listeners apart (same accept op; disambiguated by slot).
const s2s_listener_token: RingFdToken = .{ .slot = 1, .gen = 0 };
/// Reserved token for the periodic timeout sweep timer (single in-flight timer).
const timer_token: RingFdToken = .{ .slot = 2, .gen = 0 };
/// Cadence for the periodic membership anti-entropy re-burst to S2S peers. Coarse
/// (relative to the 2s sweep) so it converges split-window gaps without churn.
const membership_resync_interval_ms: i64 = 30_000;
/// Staleness window for reaping never-retracted remote member projections from
/// each peer's RouteTable. The resync re-burst refreshes every PRESENT member's
/// local last-seen stamp to ~now every `membership_resync_interval_ms`; this window
/// is 3x that, so a live member (refreshed every 30s) is never pruned and only a
/// truly-departed member whose PART/QUIT was lost (collision-rename, USR2 churn,
/// abrupt drop) ages out instead of lingering as a zombie in NAMES/WHOIS forever.
const stale_member_ttl_ms: i64 = 90_000;
/// Max members per netsplit/netjoin IRCv3 BATCH chunk; a larger channel splits
/// across multiple batches so members past a fixed cap are never silently lost.
const mesh_batch_chunk: usize = 32;
/// Scratch size for one rendered netsplit/netjoin batch — fits `mesh_batch_chunk`
/// members at the 420-byte max prefix plus the BATCH framing.
const mesh_batch_buf_len: usize = 20480;
/// Monotonic seed for netsplit/netjoin BATCH reference tags so every emitted
/// batch gets a distinct ref even when several render in the same millisecond.
var mesh_batch_ref_seq: std.atomic.Value(u64) = .init(0);
/// Distinct accept token for the implicit-TLS client listener (:6697), so
/// handleAccept can tell it apart from the plaintext + S2S listeners.
const tls_listener_token: RingFdToken = .{ .slot = 3, .gen = 0 };
/// Reserved token for this reactor's cross-reactor wake eventfd poll. When the
/// multi-reactor model lands, another reactor `wake()`s this fd to make the loop
/// run and drain its cross-shard mailbox.
const wake_token: RingFdToken = .{ .slot = 4, .gen = 0 };
/// Distinct accept token for the secure-WebSocket (wss) browser listener, so
/// handleAccept can tell it apart from the plaintext/S2S/TLS listeners.
const ws_listener_token: RingFdToken = .{ .slot = 5, .gen = 0 };

/// Set by the SIGUSR2 handler; polled by reactor 0's housekeeping tick to fire a
/// connection-preserving Helix UPGRADE out of signal context. A process-global
/// atomic (NOT a server field) because an async-signal-safe handler may only
/// touch lock-free process-global state, never the server instance. The flag is
/// inert until `installUpgradeSignalHandler` is called at boot, so tests (which
/// never install it) never trip the poll.
var upgrade_signal_requested = std.atomic.Value(bool).init(false);

/// SIGUSR2 handler — async-signal-safe: records the request and returns. The
/// re-exec runs later on reactor 0's loop (`onTimerTick`), so a shell-driven
/// deploy (`systemctl kill -s USR2 orochi`) hot-upgrades the daemon while
/// preserving every live client session, instead of dropping them all with a
/// hard `systemctl restart`.
fn onUpgradeSignal(_: posix.SIG) callconv(.c) void {
    upgrade_signal_requested.store(true, .seq_cst);
}

/// Install the SIGUSR2 → UPGRADE handler. Linux-only (UPGRADE itself is); a
/// no-op elsewhere. Call once at boot. SA_RESTART keeps the signal from
/// EINTR-storming the reactors' blocking syscalls — the upgrade is observed on
/// the next ≤2s housekeeping tick, which is ample for a deploy.
pub fn installUpgradeSignalHandler() void {
    if (comptime builtin.os.tag != .linux) return;
    const act = posix.Sigaction{
        .handler = .{ .handler = onUpgradeSignal },
        .mask = posix.sigemptyset(),
        .flags = posix.SA.RESTART,
    };
    posix.sigaction(posix.SIG.USR2, &act, null);
}

/// Set SIGPIPE's disposition to ignore (process-global, idempotent). A
/// peer-closed raw socket write then returns EPIPE instead of killing the
/// process. Called from Server.init so both the daemon and test binaries are
/// covered.
fn ignoreSigpipe() void {
    if (comptime builtin.os.tag != .linux) return;
    const act = posix.Sigaction{
        .handler = .{ .handler = posix.SIG.IGN },
        .mask = posix.sigemptyset(),
        .flags = 0,
    };
    posix.sigaction(posix.SIG.PIPE, &act, null);
}

/// Operational server log line (boot banners, mesh/media/upgrade notices). Routes
/// to stderr in a real daemon, but is SILENT under `zig test`.
///
/// Why silent in tests: zig 0.16's `--listen=-` test runner reads the test
/// binary's stderr, and ANY stderr output from a test (even one line) makes the
/// build emit a spurious "failed command" line — the step and the whole build
/// still succeed (verified: `--summary all` reports success, all tests pass, the
/// process exits 0), but the noise is misleading. The threaded-server tests boot
/// real servers and these banners flooded stderr, so the default `zig build test`
/// always printed it. Suppressing operational logs in test builds keeps the
/// output clean without changing production behavior or gating any test.
fn srvLog(comptime fmt: []const u8, args: anytype) void {
    dlog.log(fmt, args);
}
// Timeout-sweep period and IP-reputation penalty weights are operator-tunable
// via `[limits].sweep_interval` and `[reputation]` (see Config fields).
const default_reply_bytes: usize = 8192;
/// Pre-registration SendQ ceiling, used until a connection is matched to a class
/// (which sets its real `sendq_cap`). Generous so a handshake/MOTD burst never
/// trips before the class is known.
const default_sendq_cap: usize = 1 << 20; // 1 MiB
const default_recv_bytes: usize = 4096;
/// Upper bound on records demuxed in one kTLS-RX control-record drain pass, so a
/// peer that streams control records can never spin the reactor on one conn. A
/// clean stream hits `.would_block` long before this; the cap is only a safety net.
const ktls_control_drain_max: usize = 16;
const default_line_bytes: usize = irc_line.MAX_LINE_BODY + 2;
/// Default inbound RecvQ ceiling: the physical inline line buffer. A connection
/// class may raise it (lines spill to a heap overflow) or lower it; `0` in the
/// class policy means "use this default". Preserves the historical single-line
/// LineTooLong bound when no class overrides recvq.
const default_recvq_cap: usize = default_line_bytes;
const server_name = "orochi.local";
const default_host = "localhost";

/// Number of channels tracked for the fantasy-bot per-channel cooldown.
const fantasy_cooldown_slots = 64;
/// One tracked channel's last fantasy-bot reply time.
const FantasyCooldown = struct { key: [64]u8 = undefined, len: usize = 0, ts_ms: i64 = 0 };

