/// Drive a live client through SASL PLAIN as the "admin" oper account. Call
/// before NICK/USER so the client is elevated automatically at registration.
fn saslAdminPrelude(fd: linux.fd_t) ServerError!void {
    try saslPlainPrelude(fd, "admin", "orochi");
}

fn saslPlainPrelude(fd: linux.fd_t, account: []const u8, password: []const u8) ServerError!void {
    try saslPlainPreludeWithCaps(fd, account, password, "");
}

fn saslPlainPreludeWithCaps(fd: linux.fd_t, account: []const u8, password: []const u8, extra_caps: []const u8) ServerError!void {
    var plain: [128]u8 = undefined;
    if (account.len + password.len + 2 > plain.len) return error.OutputTooSmall;
    var plain_len: usize = 0;
    plain[plain_len] = 0;
    plain_len += 1;
    @memcpy(plain[plain_len .. plain_len + account.len], account);
    plain_len += account.len;
    plain[plain_len] = 0;
    plain_len += 1;
    @memcpy(plain[plain_len .. plain_len + password.len], password);
    plain_len += password.len;
    var b64: [64]u8 = undefined;
    const enc = std.base64.standard.Encoder.encode(&b64, plain[0..plain_len]);
    var line: [128]u8 = undefined;
    if (extra_caps.len == 0) {
        try writeAllFd(fd, "CAP REQ :sasl\r\n");
    } else {
        try writeAllFd(fd, std.fmt.bufPrint(&line, "CAP REQ :sasl {s}\r\n", .{extra_caps}) catch return error.OutputTooSmall);
    }
    try writeAllFd(fd, "AUTHENTICATE PLAIN\r\n");
    try writeAllFd(fd, std.fmt.bufPrint(&line, "AUTHENTICATE {s}\r\n", .{enc}) catch return error.OutputTooSmall);
    try writeAllFd(fd, "CAP END\r\n");
}

fn saslOAuthBearerPrelude(fd: linux.fd_t, token: []const u8) ServerError!void {
    var raw: [256]u8 = undefined;
    const msg = std.fmt.bufPrint(&raw, "n,,\x01auth=Bearer {s}\x01\x01", .{token}) catch return error.OutputTooSmall;
    var b64: [384]u8 = undefined;
    const enc = std.base64.standard.Encoder.encode(&b64, msg);
    var line: [512]u8 = undefined;
    try writeAllFd(fd, "CAP REQ :sasl\r\n");
    try writeAllFd(fd, "AUTHENTICATE OAUTHBEARER\r\n");
    try writeAllFd(fd, std.fmt.bufPrint(&line, "AUTHENTICATE {s}\r\n", .{enc}) catch return error.OutputTooSmall);
    try writeAllFd(fd, "CAP END\r\n");
}

fn connectLoopback(port: u16) ServerError!linux.fd_t {
    if (comptime builtin.os.tag == .linux) {
        const fd = try socketTcp();
        errdefer closeFd(fd);
        var addr = try sockaddrIn("127.0.0.1", port);
        const rc = linux.connect(fd, @ptrCast(&addr), @sizeOf(posix.sockaddr.in));
        switch (posix.errno(rc)) {
            .SUCCESS => return fd,
            .CONNREFUSED => return error.ConnectionRefused,
            .ACCES, .PERM => return error.PermissionDenied,
            else => return error.Unexpected,
        }
    } else return error.Unsupported;
}

fn writeAllFd(fd: linux.fd_t, bytes: []const u8) ServerError!void {
    var sent: usize = 0;
    while (sent < bytes.len) {
        const rc = linux.write(fd, bytes[sent..].ptr, bytes.len - sent);
        switch (posix.errno(rc)) {
            .SUCCESS => sent += @intCast(rc),
            .CONNRESET => return error.ConnectionReset,
            else => return error.Unexpected,
        }
    }
}

fn readFd(fd: linux.fd_t, buf: []u8) ServerError!usize {
    const n = posix.read(fd, buf) catch |err| switch (err) {
        error.ConnectionResetByPeer => return error.ConnectionReset,
        error.WouldBlock => return error.Unexpected,
        else => return error.Unexpected,
    };
    return n;
}

fn closeFd(fd: linux.fd_t) void {
    // Force FIN to the peer and complete any in-flight recv NOW. An io_uring
    // recv SQE holds a reference to the socket's `struct file`, so a bare
    // close(fd) only drops the fd-table entry — the socket lingers (no FIN)
    // until that pending op is canceled. shutdown() releases it immediately:
    // the peer sees EOF and the pending recv reaps with res=0 (its slot is
    // already freed, so the completion is harmlessly ignored).
    _ = linux.shutdown(fd, linux.SHUT.RDWR);
    _ = linux.close(fd);
}

const TestSink = struct {
    storage: []u8,
    used: usize = 0,

    fn write(self: *TestSink, bytes: []const u8) ServerError!void {
        if (self.used + bytes.len > self.storage.len) return error.OutputTooSmall;
        @memcpy(self.storage[self.used .. self.used + bytes.len], bytes);
        self.used += bytes.len;
    }

    fn written(self: *const TestSink) []const u8 {
        return self.storage[0..self.used];
    }
};

fn expectContains(haystack: []const u8, needle: []const u8) !void {
    try std.testing.expect(std.mem.indexOf(u8, haystack, needle) != null);
}

fn expectCodesInOrder(haystack: []const u8, codes: []const []const u8) !void {
    var pos: usize = 0;
    for (codes) |code| {
        const found = std.mem.indexOfPos(u8, haystack, pos, code) orelse return error.TestExpectedEqual;
        pos = found + code.len;
    }
}

fn expectDigitAfter(haystack: []const u8, marker: []const u8) !void {
    const pos = (std.mem.indexOf(u8, haystack, marker) orelse return error.TestExpectedEqual) + marker.len;
    try std.testing.expect(pos < haystack.len);
    try std.testing.expect(std.ascii.isDigit(haystack[pos]));
}

fn expectNoEmptyIrcLine(haystack: []const u8) !void {
    try std.testing.expect(std.mem.indexOf(u8, haystack, "\r\n\r\n") == null);
}

fn countOccurrences(haystack: []const u8, needle: []const u8) usize {
    var count: usize = 0;
    var pos: usize = 0;
    while (std.mem.indexOfPos(u8, haystack, pos, needle)) |found| {
        count += 1;
        pos = found + needle.len;
    }
    return count;
}

fn fixedHexAfter(haystack: []const u8, marker: []const u8, hex_len: usize) ?[]const u8 {
    const start = (std.mem.indexOf(u8, haystack, marker) orelse return null) + marker.len;
    if (start + hex_len > haystack.len) return null;
    const out = haystack[start .. start + hex_len];
    for (out) |ch| {
        if (!std.ascii.isHex(ch)) return null;
    }
    return out;
}

fn addTestLocalClient(server: *Server, nick: []const u8, account: ?[]const u8) !client_model.ClientId {
    if (comptime builtin.os.tag == .linux) {
        const id = try server.rx().clients.alloc(ConnState.init(-1));
        const conn = server.rx().clients.get(id).?;
        conn.token = try tokenFromId(id);
        try conn.session.setNick(nick);
        if (account) |acct| conn.session.loginAs(acct);
        try server.world.registerNick(nick, worldIdFromClient(id));
        if (account != null) server.trackSession(id, conn);
        return id;
    } else return error.SkipZigTest;
}

const LiveClient = struct {
    fd: linux.fd_t,
    buf: [default_reply_bytes]u8 = undefined,
    len: usize = 0,

    fn readAvailable(self: *LiveClient) ServerError!void {
        if (comptime builtin.os.tag == .linux) {
            while (true) {
                var fds = [_]posix.pollfd{.{
                    .fd = self.fd,
                    .events = linux.POLL.IN,
                    .revents = 0,
                }};
                const ready = posix.poll(&fds, 0) catch return error.Unexpected;
                if (ready == 0 or (fds[0].revents & linux.POLL.IN) == 0) return;
                if (self.len == self.buf.len) return error.OutputTooSmall;
                const n = try readFd(self.fd, self.buf[self.len..]);
                if (n == 0) return;
                self.len += n;
            }
        } else return error.Unsupported;
    }

    fn written(self: *const LiveClient) []const u8 {
        return self.buf[0..self.len];
    }

    fn reset(self: *LiveClient) void {
        self.len = 0;
    }
};

test "remoteGrantWhoisStatus maps grant privilege bits to WHOIS 313 flags" {
    // No grant bits (revocation tombstone): no operator line at all.
    const none = remoteGrantWhoisStatus(0);
    try std.testing.expect(!none.is_oper and !none.is_admin);

    // oper_override alone: "is an IRC operator".
    const override_bits = oper_mod.OperPrivileges.initMany(&.{.oper_override}).toBits();
    const oper_only = remoteGrantWhoisStatus(override_bits);
    try std.testing.expect(oper_only.is_oper);
    try std.testing.expect(!oper_only.is_admin);

    // server_admin upgrades the wording to Network Administrator.
    const admin_bits = oper_mod.OperPrivileges.initMany(&.{ .oper_override, .server_admin }).toBits();
    const admin = remoteGrantWhoisStatus(admin_bits);
    try std.testing.expect(admin.is_oper);
    try std.testing.expect(admin.is_admin);

    // server_admin without oper_override still renders the operator line.
    const admin_only = remoteGrantWhoisStatus(oper_mod.OperPrivileges.initMany(&.{.server_admin}).toBits());
    try std.testing.expect(admin_only.is_oper);
    try std.testing.expect(admin_only.is_admin);

    // Unrelated privileges (no override/admin) stay silent in WHOIS.
    const plain = remoteGrantWhoisStatus(oper_mod.OperPrivileges.initMany(&.{.client_kill}).toBits());
    try std.testing.expect(!plain.is_oper and !plain.is_admin);
}

test "REHASH oper binding builder preserves configured group privileges" {
    const text =
        \\[node]
        \\id = 1
        \\[listen]
        \\irc = 6680
        \\[[oper_groups]]
        \\name = "observer"
        \\privileges = ["audit_read"]
        \\[[oper_groups]]
        \\name = "admin"
        \\inherits = "observer"
        \\privileges = ["server_rehash"]
        \\[[opers]]
        \\account = "alice"
        \\class = "admin"
        \\title = "Network Guardian"
        \\
    ;
    var parsed = try config_format.parseToml(std.testing.allocator, text, .{});
    defer parsed.deinit(std.testing.allocator);
    const bindings = try buildOperBindingsFromConfig(std.testing.allocator, parsed);
    defer std.testing.allocator.free(bindings);

    const registry = try oper_mod.OperRegistry.init(bindings);
    const grant = try registry.elevateAuthenticated(.{ .name = "alice" });
    try std.testing.expect(grant.privileges.has(.server_rehash));
    try std.testing.expect(grant.privileges.has(.audit_read));
    try std.testing.expect(!grant.privileges.has(.server_admin));
    try std.testing.expectEqualStrings("Network Guardian", grant.title);
}

test "REHASH oper binding builder skips unknown or empty classes" {
    const text =
        \\[node]
        \\id = 1
        \\[listen]
        \\irc = 6680
        \\[[oper_groups]]
        \\name = "empty"
        \\privileges = []
        \\[[opers]]
