    try writeAllFd(fd_b, "CAP REQ :orochi/topics\r\nNICK B\r\nUSER bob 0 * :Bob\r\nCAP END\r\n");
    try writeAllFd(fd_c, "NICK C\r\nUSER carol 0 * :Carol\r\n");
