        };
        defer server.deinit();

        try std.testing.expectEqual(@as(usize, 0), server.warden.count());

        // A received mesh-WARD add is enforced locally as a mesh-scope ward.
        server.applyRemoteWard(.{
            .op = .add,
            .match = .mask,
            .pattern = "*!*@*.evil.example",
            .action = .expel,
            .reason = "spam ring",
            .set_by = "oper!~o@peer",
            .created_ms = 1,
            .expires_ms = 0,
        });
        try std.testing.expectEqual(@as(usize, 1), server.warden.count());
        const hit = server.warden.check(.{ .mask = "bob!~b@host.evil.example" }, 100).?;
        try std.testing.expectEqual(warden.Scope.mesh, hit.scope);
        try std.testing.expectEqual(warden.Action.expel, hit.action);

        // A received mesh-WARD remove forgets it (only op/match/pattern load-bearing).
        server.applyRemoteWard(.{
            .op = .remove,
            .match = .mask,
            .pattern = "*!*@*.evil.example",
            .action = .expel,
            .reason = "",
            .set_by = "",
            .created_ms = 0,
            .expires_ms = 0,
        });
        try std.testing.expectEqual(@as(usize, 0), server.warden.count());
        try std.testing.expect(server.warden.check(.{ .mask = "bob!~b@host.evil.example" }, 100) == null);
    } else return error.SkipZigTest;
}

test "rotatable cloak key: a ward on the old-key cloak misses the new-key cloak" {
    // The premise behind enforceWard's previous-key fallback: rotating the cloak
    // secret changes every client's IP cloak, so a WARD written against the OLD
    // cloak no longer matches the NEW one. enforceWard therefore re-checks the
    // host/mask facets recomputed under cloak_prev_key (mirroring prevKeyCloakHost).
    var old_bytes: [cloak.key_len]u8 = undefined;
    var new_bytes: [cloak.key_len]u8 = undefined;
    @memset(&old_bytes, 0xA1);
    @memset(&new_bytes, 0x5C);
    const old_key = cloak.SecretKey.init(old_bytes);
    const new_key = cloak.SecretKey.init(new_bytes);

    var ob: [cloak.max_cloak_len]u8 = undefined;
    var nb: [cloak.max_cloak_len]u8 = undefined;
    const old_host = try cloak.cloak(&ob, &old_key, "198.51.100.7", cloak.Geo.none, .{});
    const new_host = try cloak.cloak(&nb, &new_key, "198.51.100.7", cloak.Geo.none, .{});
    try std.testing.expect(!std.mem.eql(u8, old_host, new_host));

    var reg = warden.Registry.init(std.testing.allocator, .{});
    defer reg.deinit();
    try reg.add(.{ .match = .host, .pattern = old_host, .action = .expel, .reason = "rotate", .set_by = "oper" });

    // The old-key host still hits the ban; the post-rotation new-key host does
    // NOT — which is exactly why the server must also test the previous-key host.
    try std.testing.expect(reg.check(.{ .host = old_host }, 100) != null);
    try std.testing.expect(reg.check(.{ .host = new_host }, 100) == null);
}

// Build a relay PRIVMSG signed by `kp`, stamping the carried pubkey/sig into the
// caller-owned `pk_buf`/`sig_buf` (which must outlive any deliverRelay call). The
// `origin_node` is the self-certified short id of `kp`, so a receiver's
// `originShortId(pubkey) == origin_node` invariant holds.
fn buildSignedRelay(
    kp: *const sign_mod.KeyPair,
    target: []const u8,
    source_prefix: []const u8,
    text: []const u8,
    hlc: u64,
    pk_buf: *[message_relay.pubkey_len]u8,
    sig_buf: *[message_relay.sig_len]u8,
) !message_relay.RelayMessage {
    var msg = message_relay.RelayMessage{
        .verb = .privmsg,
        .target = target,
        .source_nick = "Remote",
        .source_prefix = source_prefix,
        .account = "",
        .tags = "",
        .text = text,
        .origin_node = message_relay.originShortId(kp.public_key),
        .hlc = hlc,
    };
    const transcript = try message_relay.originTranscript(std.testing.allocator, msg);
    defer std.testing.allocator.free(transcript);
    try message_relay.signInPlace(&msg, kp, transcript, pk_buf, sig_buf);
    return msg;
}

const sign_mod = @import("../crypto/sign.zig");

test "deliverRelay accepts a correctly signed origin message" {
    if (comptime builtin.os.tag == .linux) {
        var server = Server.init(std.testing.allocator, .{ .host = "127.0.0.1", .port = 0 }) catch |err| switch (err) {
            error.Unsupported, error.PermissionDenied, error.SocketUnavailable => return error.SkipZigTest,
            else => return err,
        };
        defer server.deinit();

        const target_id = try addTestLocalClient(&server, "Target", "targetacct");
        const target = server.connFor(target_id).?;

        var kp = try sign_mod.KeyPair.fromSeed(@as([sign_mod.seed_len]u8, @splat(0x21)));
        defer kp.deinit();
        var pk_buf: [message_relay.pubkey_len]u8 = undefined;
        var sig_buf: [message_relay.sig_len]u8 = undefined;
        const msg = try buildSignedRelay(&kp, "Target", "Remote!r@elsewhere", "signed and delivered", 1, &pk_buf, &sig_buf);

        server.deliverRelay(msg);
        try expectContains(target.send_buf[0..target.send_len], ":Remote!r@elsewhere PRIVMSG Target :signed and delivered\r\n");
        try std.testing.expectEqual(@as(u64, 0), server.rejected_relay_signatures);
    } else return error.SkipZigTest;
}

test "deliverRelay rejects a forged signature: not delivered, counted" {
    if (comptime builtin.os.tag == .linux) {
        var server = Server.init(std.testing.allocator, .{ .host = "127.0.0.1", .port = 0 }) catch |err| switch (err) {
            error.Unsupported, error.PermissionDenied, error.SocketUnavailable => return error.SkipZigTest,
            else => return err,
        };
        defer server.deinit();

        const target_id = try addTestLocalClient(&server, "Target", "targetacct");
        const target = server.connFor(target_id).?;

        var kp = try sign_mod.KeyPair.fromSeed(@as([sign_mod.seed_len]u8, @splat(0x31)));
        defer kp.deinit();
        var pk_buf: [message_relay.pubkey_len]u8 = undefined;
        var sig_buf: [message_relay.sig_len]u8 = undefined;
        var msg = try buildSignedRelay(&kp, "Target", "Remote!r@elsewhere", "forged body", 2, &pk_buf, &sig_buf);
        // Tamper the text AFTER signing: structure is valid, signature no longer is.
        msg.text = "tampered body the origin never authored";

        server.deliverRelay(msg);
        try std.testing.expectEqual(@as(usize, 0), target.send_len);
        try std.testing.expectEqual(@as(u64, 1), server.rejected_relay_signatures);
    } else return error.SkipZigTest;
}

