    var a = LiveClient{ .fd = fd_a };
    var b = LiveClient{ .fd = fd_b };

    try writeAllFd(fd_a, "NICK trev\r\nUSER trev 0 * :Trev\r\n");
    try recvUntil(&a, " 001 trev ", 200);
    try writeAllFd(fd_a, "REGISTER trev * correcthorse\r\n");
