test "threaded server: OROWASM reports ABI budgets and plugin registrations to opers" {
    var cfg = operTestConfig(0);
    cfg.wasm_max_plugin_bytes = 4096;
    cfg.wasm_max_memory_bytes = 128 * 1024;
    cfg.wasm_default_fuel = 1234;
    cfg.wasm_allowed_caps = wasm_abi.CapabilitySet.initMany(&.{ .reply, .hooks });
    var guard_digest: [std.crypto.hash.Blake3.digest_length]u8 = undefined;
    std.crypto.hash.Blake3.hash(wasm_bridge.testing.stop_hook_wasm, &guard_digest, .{});
    var publisher = try crypto_sign.KeyPair.fromSeed(@as([crypto_sign.seed_len]u8, @splat(0x61)));
    defer publisher.deinit();
    var registry_pin = wasm_bridge.RegistryPin{ .name = "guard", .blake3 = guard_digest, .tier = .verified, .publisher = publisher.public_key };
    var transcript_buf: [1024]u8 = undefined;
    const transcript = try wasm_bridge.registryPinTranscript(&transcript_buf, registry_pin);
    registry_pin.signature = try publisher.signCtx(wasm_bridge.registry_signature_domain, transcript);
    const registry_pins = [_]wasm_bridge.RegistryPin{registry_pin};
    cfg.wasm_registry = &registry_pins;
    const revoked_hashes = [_][std.crypto.hash.Blake3.digest_length]u8{@as([std.crypto.hash.Blake3.digest_length]u8, @splat(0xaa))};
    cfg.wasm_revoked_hashes = &revoked_hashes;
    cfg.wasm_disabled_plugins = &.{"bad"};
    var server = Server.init(std.testing.allocator, cfg) catch |err| switch (err) {
        error.Unsupported, error.PermissionDenied, error.SocketUnavailable => return error.SkipZigTest,
        else => return err,
    };
    defer server.deinit();
    try std.testing.expectError(error.PluginDisabled, server.wasm.loadBytes("bad", wasm_bridge.testing.stop_hook_wasm));
    try server.wasm.loadBytes("guard", wasm_bridge.testing.stop_hook_wasm);
    const port = try server.boundPort();

    var run = std.atomic.Value(bool).init(true);
    var thr = try std.Thread.spawn(.{}, Server.runThreaded, .{ &server, &run });
    defer {
        run.store(false, .release);
        if (connectLoopback(port)) |wfd| closeFd(wfd) else |_| {}
        thr.join();
    }

    const fd_user = connectLoopback(port) catch return error.SkipZigTest;
    defer closeFd(fd_user);
    var user = LiveClient{ .fd = fd_user };
    try writeAllFd(fd_user, "NICK User\r\nUSER user 0 * :User\r\n");
    try recvUntil(&user, " 001 User ", 200);
    user.reset();
    try writeAllFd(fd_user, "OROWASM STATUS\r\n");
    try recvUntil(&user, " 481 User ", 200);

    const fd_admin = connectLoopback(port) catch return error.SkipZigTest;
    defer closeFd(fd_admin);
    var admin = LiveClient{ .fd = fd_admin };
    try saslAdminPrelude(fd_admin);
    try writeAllFd(fd_admin, "NICK Oper\r\nUSER oper 0 * :Oper\r\n");
    try recvUntil(&admin, " 381 Oper ", 200);

    admin.reset();
    try writeAllFd(fd_admin, "OROWASM STATUS\r\n");
    try recvUntil(&admin, "OroWasm runtime status", 200);
    try recvUntil(&admin, "plugins=1 commands=0 hooks=1 allowed_caps=reply,hooks allowed_intents=(none) registry_pins=1 signed_pins=1 revoked_hashes=1 disabled_plugins=1 blocked_loads=1", 200);
    try recvUntil(&admin, "budgets max_plugin_bytes=4096 max_memory_bytes=131072 default_fuel=1234", 200);

    admin.reset();
    try writeAllFd(fd_admin, "OROWASM ABI\r\n");
    try recvUntil(&admin, "manifest_schema=1.0 host_functions=9 allowed_caps=reply,hooks allowed_intents=(none)", 200);
    try recvUntil(&admin, "hostcall reply v1.0 cap=reply", 200);
    try recvUntil(&admin, "hostcall net_connect v1.0 cap=net:outbound min_tier=verified", 200);
    try recvUntil(&admin, "intent message-content min_tier=verified", 200);

    admin.reset();
    try writeAllFd(fd_admin, "OROWASM WIT\r\n");
    try recvUntil(&admin, "OroWasm ABI WIT v1", 200);
    try recvUntil(&admin, "package orochi:orowasm@1.0.0;", 200);
    try recvUntil(&admin, "net-connect: func(host: string, port: u16)", 200);

    admin.reset();
    try writeAllFd(fd_admin, "OROWASM PLUGINS\r\n");
    try recvUntil(&admin, "handle=1 name=guard tier=verified signed=true commands=0 hooks=1 grants=(none) intents=(none)", 200);
