test "threaded server: cross-shard PRIVMSG delivery (num_shards=2)" {
    if (comptime builtin.os.tag == .linux) {
        // Two reactor threads, SO_REUSEPORT listeners — the kernel may place each
        // client on either reactor. Several clients in one channel raise the odds two
        // of them land on DIFFERENT shards; a PRIVMSG must still reach every member,
        // which exercises the cross-shard fabric handoff end to end. Repeated rounds
        // make a race-driven drop/dup fail rather than slip through.
        var server = Server.init(std.testing.allocator, .{
            .host = "127.0.0.1",
            .port = 0,
            .num_shards = 2,
        }) catch |err| switch (err) {
            // No io_uring / no perms / no SO_REUSEPORT in this sandbox: skip, don't fail.
            error.Unsupported, error.PermissionDenied, error.SocketUnavailable, error.AddressInUse => return error.SkipZigTest,
            else => return err,
        };
        defer server.deinit();
        // A single reactor (clamped, or fabric/pool unavailable) cannot test cross
        // shard; skip so this only asserts when the multi-reactor topology is live.
        if (server.reactors.len < 2) return error.SkipZigTest;
        const port = try server.boundPort();

        var run = std.atomic.Value(bool).init(true);
        var thr = try std.Thread.spawn(.{}, Server.runThreaded, .{ &server, &run });
        defer {
            // Clear the flag AND wake every reactor's wake eventfd. A SO_REUSEPORT
            // throwaway connection only nudges whichever reactor the kernel routes it
            // to; the other worker would stay blocked in submitAndWait forever and
            // pool.join() would hang. wakeAllReactors makes every blocked loop return,
            // observe run==false, and exit so the join (and this thread) completes.
            server.requestStop(&run);
            thr.join();
        }

        // Connect a handful of clients; with round-robin kernel placement across two
        // reactors this all-but-guarantees the channel spans both shards.
        const n_clients = 6;
        var fds: [n_clients]linux.fd_t = undefined;
        var clients: [n_clients]LiveClient = undefined;
        var connected: usize = 0;
        defer for (fds[0..connected]) |fd| closeFd(fd);
        for (0..n_clients) |i| {
            fds[i] = connectLoopback(port) catch |err| switch (err) {
                error.PermissionDenied, error.SocketUnavailable, error.ConnectionRefused => return error.SkipZigTest,
                else => return err,
            };
            connected += 1;
            clients[i] = LiveClient{ .fd = fds[i] };
        }

        // Register each client with a distinct nick and join the shared channel.
        var nick_buf: [n_clients][8]u8 = undefined;
        for (0..n_clients) |i| {
            const nick = std.fmt.bufPrint(&nick_buf[i], "U{d}", .{i}) catch unreachable;
            var reg_buf: [64]u8 = undefined;
            const reg = std.fmt.bufPrint(&reg_buf, "NICK {s}\r\nUSER u{d} 0 * :User {d}\r\n", .{ nick, i, i }) catch unreachable;
            try writeAllFd(fds[i], reg);
        }
        for (0..n_clients) |i| {
            var need: [12]u8 = undefined;
            const needle = std.fmt.bufPrint(&need, " 001 U{d} ", .{i}) catch unreachable;
            try recvUntil(&clients[i], needle, 400);
        }
        for (0..n_clients) |i| {
            try writeAllFd(fds[i], "JOIN #shard\r\n");
            var need: [20]u8 = undefined;
            const needle = std.fmt.bufPrint(&need, " 366 U{d} #shard ", .{i}) catch unreachable;
            try recvUntil(&clients[i], needle, 400);
        }

        // Several rounds: each round a different sender messages the channel; every
        // OTHER client must receive it. A line that crossed shards rode the fabric.
        const rounds = 4;
        for (0..rounds) |r| {
            const sender = r % n_clients;
            for (0..n_clients) |i| clients[i].reset();
            var line_buf: [48]u8 = undefined;
            const line = std.fmt.bufPrint(&line_buf, "PRIVMSG #shard :round{d}\r\n", .{r}) catch unreachable;
            try writeAllFd(fds[sender], line);

            var exp_buf: [40]u8 = undefined;
            const expected = std.fmt.bufPrint(&exp_buf, "PRIVMSG #shard :round{d}\r\n", .{r}) catch unreachable;
            for (0..n_clients) |i| {
                if (i == sender) continue;
                // Whether U{i} shares the sender's reactor or not, the message must
                // arrive — proving local AND cross-shard delivery in one assertion.
                try recvUntil(&clients[i], expected, 400);
            }
        }
    } else return error.SkipZigTest;
}

test "threaded server: oper EVENT delivery + cross-shard fan-out under num_shards=2" {
    if (comptime builtin.os.tag == .linux) {
        // Exercises the multi-reactor oper-event path: several SASL-admin opers (all
        // auto-subscribed on elevation), one broadcasts, and EVERY oper must receive
        // it. publishOperEvent delivers locally AND fans the event to other shards'
        // inboxes; each reactor delivers to its own subscribers on its own thread.
        // This sandbox's SO_REUSEPORT routes all loopback accepts to one shard,
        // so the cross-shard RECEIVE side is mechanism-verified by instrumentation
        // rather than guaranteed exercised here; what this test does guarantee is that
        // the fan-out code path runs without breaking local delivery, and that an oper
        // reliably receives its own and a sibling's announce under sharding.
        var cfg = operTestConfig(0);
        cfg.num_shards = 2;
        var server = Server.init(std.testing.allocator, cfg) catch |err| switch (err) {
            error.Unsupported, error.PermissionDenied, error.SocketUnavailable, error.AddressInUse => return error.SkipZigTest,
            else => return err,
        };
        defer server.deinit();
        if (server.reactors.len < 2) return error.SkipZigTest;
        const port = try server.boundPort();
        var run = std.atomic.Value(bool).init(true);
        var thr = try std.Thread.spawn(.{}, Server.runThreaded, .{ &server, &run });
        defer {
            server.requestStop(&run);
            thr.join();
        }

        const n_opers = 4;
        var fds: [n_opers]linux.fd_t = undefined;
        var clients: [n_opers]LiveClient = undefined;
        var connected: usize = 0;
        defer for (fds[0..connected]) |fd| closeFd(fd);
        for (0..n_opers) |i| {
            fds[i] = connectLoopback(port) catch |err| switch (err) {
                error.PermissionDenied, error.SocketUnavailable, error.ConnectionRefused => return error.SkipZigTest,
                else => return err,
            };
            connected += 1;
            clients[i] = LiveClient{ .fd = fds[i] };
            try saslAdminPrelude(fds[i]);
            var reg_buf: [48]u8 = undefined;
            const reg = try std.fmt.bufPrint(&reg_buf, "NICK O{d}\r\nUSER u{d} 0 * :O{d}\r\n", .{ i, i, i });
            try writeAllFd(fds[i], reg);
        }
        for (0..n_opers) |i| {
            var need_buf: [16]u8 = undefined;
            const need = try std.fmt.bufPrint(&need_buf, " 381 O{d} ", .{i});
            try recvUntil(&clients[i], need, 400);
        }

        // O0 opts into IRCX (EVENT is IRCX-gated) and broadcasts.
        try writeAllFd(fds[0], "IRCX\r\n");
        try recvUntil(&clients[0], " 800 O0 ", 300);
        for (0..n_opers) |i| clients[i].reset();
        try writeAllFd(fds[0], "EVENT BROADCAST :crossshard\r\n");

        // Every oper receives the announce. The chatsvc line is
        // `:<srv> EVENT <oper-nick> <sender-mask>: <message>`, so match the raw EVENT
        // wrapper and the message text separately (the target + mask sit between them).
        for (0..n_opers) |i| {
            try recvUntil(&clients[i], " EVENT ", 500);
            try recvUntil(&clients[i], "crossshard", 500);
        }
    } else return error.SkipZigTest;
}

test "event routing: IRCX type subscriptions are token-routed with no category cross-talk" {
    // The core delivery-filter contract: an IRCX EVENT subscriber matches events
    // by the body's leading TYPE token (CHANNEL/MEMBER/USER), independent of the
    // daemon EventCategory the event was published under. This eliminates the
    // old cross-talk where MEMBER and USER both rode OPER_ACTION.
    var user_sub = dispatch.ClientSession.init();
    try user_sub.setIrcxEventSubscription(.user, "*");
    // USER-typed events match (even though they publish under different
    // categories: CONNECT under .connect, NICK under .oper_action).
    try std.testing.expect(LinuxServer.sessionWantsEvent(&user_sub, .connect, .notice, "USER CONNECT n!u@h", "n!u@h"));
    try std.testing.expect(LinuxServer.sessionWantsEvent(&user_sub, .oper_action, .notice, "USER NICK old!u@h -> new", "old!u@h"));
    try std.testing.expect(LinuxServer.sessionWantsEvent(&user_sub, .oper_action, .notice, "USER OPER n!u@h :Net Admin", "n!u@h"));
    // The regression guard: a USER subscriber must NOT receive MEMBER or CHANNEL
    // lines, nor non-IRCX oper prose, despite shared categories.
    try std.testing.expect(!LinuxServer.sessionWantsEvent(&user_sub, .oper_action, .notice, "MEMBER JOIN #c nick", "#c"));
    try std.testing.expect(!LinuxServer.sessionWantsEvent(&user_sub, .announce, .notice, "CHANNEL MODE #c +nt", "#c"));
    try std.testing.expect(!LinuxServer.sessionWantsEvent(&user_sub, .kill, .notice, "k killed s (flood)", "k killed s (flood)"));

    // Category-plane severity filter: a KILL subscriber with a min-severity of
    // .warn receives .warn/.error/.critical kills but drops .notice/.info ones,
    // while the IRCX plane is unaffected by severity.
    var cat_sub = dispatch.ClientSession.init();
    cat_sub.setEventMask(event_spine.CategoryMask.only(.kill));
    // Default min severity (.debug) delivers everything.
    try std.testing.expect(LinuxServer.sessionWantsEvent(&cat_sub, .kill, .notice, "k killed s", "k killed s"));
    cat_sub.setEventMinSeverity(.warn);
    try std.testing.expect(LinuxServer.sessionWantsEvent(&cat_sub, .kill, .warn, "k killed s", "k killed s"));
    try std.testing.expect(LinuxServer.sessionWantsEvent(&cat_sub, .kill, .critical, "k killed s", "k killed s"));
    try std.testing.expect(!LinuxServer.sessionWantsEvent(&cat_sub, .kill, .notice, "k killed s", "k killed s"));
    try std.testing.expect(!LinuxServer.sessionWantsEvent(&cat_sub, .kill, .info, "k killed s", "k killed s"));

    // A MEMBER subscriber receives only MEMBER-typed events — not USER NICK,
    // which previously leaked because both used OPER_ACTION.
    var member_sub = dispatch.ClientSession.init();
    try member_sub.setIrcxEventSubscription(.member, "*");
    try std.testing.expect(LinuxServer.sessionWantsEvent(&member_sub, .oper_action, .notice, "MEMBER JOIN #c nick", "#c"));
    try std.testing.expect(LinuxServer.sessionWantsEvent(&member_sub, .oper_action, .notice, "MEMBER KNOCK #c nick :let me in", "#c"));
    try std.testing.expect(!LinuxServer.sessionWantsEvent(&member_sub, .oper_action, .notice, "USER NICK old!u@h -> new", "old!u@h"));
    try std.testing.expect(!LinuxServer.sessionWantsEvent(&member_sub, .connect, .notice, "USER CONNECT n!u@h", "n!u@h"));

    // Subject globs still scope IRCX matches by channel/mask.
    var scoped = dispatch.ClientSession.init();
    try scoped.setIrcxEventSubscription(.channel, "#ops*");
    try std.testing.expect(LinuxServer.sessionWantsEvent(&scoped, .announce, .notice, "CHANNEL MODE #ops-eu +i", "#ops-eu"));
    try std.testing.expect(!LinuxServer.sessionWantsEvent(&scoped, .announce, .notice, "CHANNEL MODE #lobby +i", "#lobby"));
}

test "event routing: legacy oper category subscriptions are independent of the IRCX plane" {
    // An oper subscribed to a category (e.g. via [[opers]] presubscribe) with NO
    // IRCX EVENT subscription still matches purely by category, and an IRCX
    // subscription never bleeds into the legacy category mask.
    var oper = dispatch.ClientSession.init();
    oper.setEventMask(event_spine.CategoryMask.only(.kill));
    try std.testing.expect(LinuxServer.sessionWantsEvent(&oper, .kill, .notice, "k killed s (flood)", "k killed s (flood)"));
    // Categories it did not subscribe to are filtered, IRCX-typed body or not.
    try std.testing.expect(!LinuxServer.sessionWantsEvent(&oper, .announce, .notice, "CHANNEL MODE #c +nt", "#c"));
    try std.testing.expect(!LinuxServer.sessionWantsEvent(&oper, .connect, .notice, "USER CONNECT n!u@h", "n!u@h"));

    // An IRCX USER subscription must not grant legacy-category delivery: a USER
    // subscriber receives a KILL-category event only if its body is USER-typed.
    var ircx = dispatch.ClientSession.init();
    try ircx.setIrcxEventSubscription(.user, "*");
    try std.testing.expect(!LinuxServer.sessionWantsEvent(&ircx, .kill, .notice, "k killed s (flood)", "k killed s (flood)"));
}

test "threaded server: founder/MODE/KICK/NAMES/WHOIS/LIST/WHO/ISON/LUSERS end-to-end" {
    var server = Server.init(std.testing.allocator, .{ .host = "127.0.0.1", .port = 0 }) catch |err| switch (err) {
        error.Unsupported, error.PermissionDenied, error.SocketUnavailable => return error.SkipZigTest,
        else => return err,
    };
    defer server.deinit();
    const port = try server.boundPort();

    var run = std.atomic.Value(bool).init(true);
    var thr = try std.Thread.spawn(.{}, Server.runThreaded, .{ &server, &run });
    defer {
        run.store(false, .release);
        if (connectLoopback(port)) |wfd| closeFd(wfd) else |_| {}
        thr.join();
    }

    const fd_a = connectLoopback(port) catch return error.SkipZigTest;
    defer closeFd(fd_a);
    const fd_b = connectLoopback(port) catch return error.SkipZigTest;
    defer closeFd(fd_b);
    var a = LiveClient{ .fd = fd_a };
    var b = LiveClient{ .fd = fd_b };

    try writeAllFd(fd_a, "NICK A\r\nUSER alice 0 * :Alice\r\n");
    try writeAllFd(fd_b, "NICK B\r\nUSER bob 0 * :Bob\r\n");
    try recvUntil(&a, " 001 A ", 200);
    try recvUntil(&b, " 001 B ", 200);

    // A founds #x -> A is FOUNDER (~). B joins -> no status.
    a.reset();
    try writeAllFd(fd_a, "JOIN #x\r\n");
    try recvUntil(&a, " 353 ", 200); // NAMES
    try recvUntil(&a, "!A", 200); // founder prefix on A
    try writeAllFd(fd_b, "JOIN #x\r\n");
    try recvUntil(&b, " 366 B #x ", 200);

    // Founder ops B: MODE #x +o B -> broadcast +o.
    a.reset();
    try writeAllFd(fd_a, "MODE #x +o B\r\n");
    try recvUntil(&a, "MODE #x +o B", 200);

    // A KICKs B (founder outranks op).
    a.reset();
    try writeAllFd(fd_a, "KICK #x B :bye\r\n");
    try recvUntil(&a, "KICK #x B :bye", 200);

    // WHOIS A -> 311 user line + 318 end.
    a.reset();
    try writeAllFd(fd_a, "WHOIS A\r\n");
    try recvUntil(&a, " 311 A A alice ", 200);
    try recvUntil(&a, " 318 A A ", 200);

    // LIST -> #x present (322).
    a.reset();
    try writeAllFd(fd_a, "LIST\r\n");
    try recvUntil(&a, " 322 A #x ", 200);

    // WHO #x -> 352 + 315 end.
    a.reset();
    try writeAllFd(fd_a, "WHO #x\r\n");
    try recvUntil(&a, " 315 A #x ", 200);

    // ISON A B -> 303 lists A (B parted via kick but reconnect-less; A online).
    a.reset();
    try writeAllFd(fd_a, "ISON A B\r\n");
    try recvUntil(&a, " 303 A :", 200);

    // LUSERS -> 251, VERSION -> 351.
    a.reset();
    try writeAllFd(fd_a, "LUSERS\r\n");
    try recvUntil(&a, " 251 A ", 200);
    a.reset();
    try writeAllFd(fd_a, "VERSION\r\n");
    try recvUntil(&a, " 351 A ", 200);
    a.reset();
    try writeAllFd(fd_a, "TIME\r\n");
    try recvUntil(&a, " 391 A ", 200);
    a.reset();
    try writeAllFd(fd_a, "ADMIN\r\n");
    try recvUntil(&a, " 256 A ", 200);
}

test "threaded server IRCX: NAMES on a secret channel hides the roster from a non-member" {
    var server = Server.init(std.testing.allocator, .{ .host = "127.0.0.1", .port = 0 }) catch |err| switch (err) {
        error.Unsupported, error.PermissionDenied, error.SocketUnavailable => return error.SkipZigTest,
        else => return err,
    };
    defer server.deinit();
    const port = try server.boundPort();

    var run = std.atomic.Value(bool).init(true);
    var thr = try std.Thread.spawn(.{}, Server.runThreaded, .{ &server, &run });
    defer {
        run.store(false, .release);
        if (connectLoopback(port)) |wfd| closeFd(wfd) else |_| {}
        thr.join();
    }

    const fd_a = connectLoopback(port) catch return error.SkipZigTest;
    defer closeFd(fd_a);
    const fd_b = connectLoopback(port) catch return error.SkipZigTest;
    defer closeFd(fd_b);
    var a = LiveClient{ .fd = fd_a };
    var b = LiveClient{ .fd = fd_b };

    try writeAllFd(fd_a, "NICK A\r\nUSER alice 0 * :Alice\r\n");
    try writeAllFd(fd_b, "NICK B\r\nUSER bob 0 * :Bob\r\n");
    try recvUntil(&a, " 001 A ", 200);
    try recvUntil(&b, " 001 B ", 200);

    // A founds #sec and marks it secret (+s). B is NOT a member.
    a.reset();
    try writeAllFd(fd_a, "JOIN #sec\r\n");
    try recvUntil(&a, " 366 A #sec ", 200);
    a.reset();
    try writeAllFd(fd_a, "MODE #sec +s\r\n");
    try recvUntil(&a, "MODE #sec +s", 200);

    // Non-member B: NAMES #sec must NOT leak the roster — only RPL_ENDOFNAMES,
    // never a 353 naming A (ShowChannel = public-channel || is-member).
    b.reset();
    try writeAllFd(fd_b, "NAMES #sec\r\n");
    try recvUntil(&b, " 366 B #sec ", 200);
    try std.testing.expect(std.mem.indexOf(u8, b.written(), " 353 ") == null);

    // Sanity: a member (A) still sees the roster for its own secret channel.
    a.reset();
    try writeAllFd(fd_a, "NAMES #sec\r\n");
    try recvUntil(&a, " 353 ", 200);
    try recvUntil(&a, " 366 A #sec ", 200);
}

