    try recvUntil(&a, " 352 A #sec ", 200);
    try recvUntil(&a, " 315 A #sec ", 200);
}

test "threaded server IRCX: bare NAMES hides a private (+p) channel from a non-member" {
    var server = Server.init(std.testing.allocator, .{ .host = "127.0.0.1", .port = 0 }) catch |err| switch (err) {
        error.Unsupported, error.PermissionDenied, error.SocketUnavailable => return error.SkipZigTest,
        else => return err,
    };
    defer server.deinit();
    const port = try server.boundPort();

    var run = std.atomic.Value(bool).init(true);
    var thr = try std.Thread.spawn(.{}, Server.runThreaded, .{ &server, &run });
    defer {
        run.store(false, .release);
        if (connectLoopback(port)) |wfd| closeFd(wfd) else |_| {}
        thr.join();
    }

    const fd_a = connectLoopback(port) catch return error.SkipZigTest;
    defer closeFd(fd_a);
    const fd_b = connectLoopback(port) catch return error.SkipZigTest;
    defer closeFd(fd_b);
    var a = LiveClient{ .fd = fd_a };
    var b = LiveClient{ .fd = fd_b };

    try writeAllFd(fd_a, "NICK A\r\nUSER alice 0 * :Alice\r\n");
    try writeAllFd(fd_b, "NICK B\r\nUSER bob 0 * :Bob\r\n");
    try recvUntil(&a, " 001 A ", 200);
    try recvUntil(&b, " 001 B ", 200);

    // A founds a private (+p, NOT secret) channel and a plain public channel.
    a.reset();
    try writeAllFd(fd_a, "JOIN #priv\r\n");
    try recvUntil(&a, " 366 A #priv ", 200);
    a.reset();
    try writeAllFd(fd_a, "MODE #priv +p\r\n");
    try recvUntil(&a, "MODE #priv +p", 200);
    a.reset();
    try writeAllFd(fd_a, "JOIN #pub\r\n");
    try recvUntil(&a, " 366 A #pub ", 200);

    // Non-member B: bare NAMES must list the public channel but NEVER the +p
    // one it is not a member of. PING round-trips as a flush barrier so all
    // NAMES output is on the wire before we assert.
    b.reset();
    try writeAllFd(fd_b, "NAMES\r\nPING :namesync\r\n");
    try recvUntil(&b, "PONG orochi.local :namesync", 200);
    try std.testing.expect(std.mem.indexOf(u8, b.written(), "#pub") != null);
    try std.testing.expect(std.mem.indexOf(u8, b.written(), "#priv") == null);

    // Sanity: the member (A) still sees its own +p channel in bare NAMES.
    a.reset();
    try writeAllFd(fd_a, "NAMES\r\nPING :namesync2\r\n");
    try recvUntil(&a, "PONG orochi.local :namesync2", 200);
    try std.testing.expect(std.mem.indexOf(u8, a.written(), "#priv") != null);
}

test "threaded server: AWAY/SETNAME/EVENT-broadcast/INFO/USERS/LINKS/MAP end-to-end" {
    var server = Server.init(std.testing.allocator, operTestConfig(0)) catch |err| switch (err) {
        error.Unsupported, error.PermissionDenied, error.SocketUnavailable => return error.SkipZigTest,
        else => return err,
    };
    defer server.deinit();
    const port = try server.boundPort();

    var run = std.atomic.Value(bool).init(true);
    var thr = try std.Thread.spawn(.{}, Server.runThreaded, .{ &server, &run });
    defer {
        run.store(false, .release);
        if (connectLoopback(port)) |wfd| closeFd(wfd) else |_| {}
        thr.join();
    }

    const fd_a = connectLoopback(port) catch return error.SkipZigTest;
    defer closeFd(fd_a);
    const fd_b = connectLoopback(port) catch return error.SkipZigTest;
    defer closeFd(fd_b);
    var a = LiveClient{ .fd = fd_a };
    var b = LiveClient{ .fd = fd_b };

    try saslPlainPreludeWithCaps(fd_a, "admin", "orochi", "setname"); // A authenticates as the admin oper account
    try writeAllFd(fd_a, "NICK A\r\nUSER alice 0 * :Alice\r\n");
    try writeAllFd(fd_b, "NICK B\r\nUSER bob 0 * :Bob\r\n");
    try recvUntil(&a, " 001 A ", 200);
    try recvUntil(&a, " 381 A ", 200); // A auto-elevated on SASL login
    try recvUntil(&b, " 001 B ", 200);
    try writeAllFd(fd_a, "IRCX\r\n");
    try writeAllFd(fd_b, "IRCX\r\n");
    try recvUntil(&a, " 800 A 1 0 ", 200);
    try recvUntil(&b, " 800 B 1 0 ", 200);

    // B marks away -> 306; A PRIVMSGs B -> A sees RPL_AWAY (301).
    b.reset();
    try writeAllFd(fd_b, "AWAY :lunch\r\n");
    try recvUntil(&b, " 306 B ", 200);
    a.reset();
    try writeAllFd(fd_a, "PRIVMSG B :hey\r\n");
    try recvUntil(&a, " 301 A B :lunch\r\n", 200);
    // B returns -> 305.
    b.reset();
    try writeAllFd(fd_b, "AWAY\r\n");
    try recvUntil(&b, " 305 B ", 200);

    // SETNAME echoes back to the sender.
    a.reset();
    try writeAllFd(fd_a, "SETNAME :Alice Liddell\r\n");
    try recvUntil(&a, "SETNAME :Alice Liddell\r\n", 200);

    // A non-oper (B) cannot use EVENT -> 481 (wallops is folded into EVENT).
    b.reset();
    try writeAllFd(fd_b, "EVENT BROADCAST :nope\r\n");
    try recvUntil(&b, " 481 B ", 200);
    // WHOIS now shows the operator line (313).
    a.reset();
    try writeAllFd(fd_a, "WHOIS A\r\n");
    try recvUntil(&a, " 313 A A ", 200);
    a.reset();
    // EVENT BROADCAST (the former WALLOPS) is delivered as an oper-visible Event
    // Spine announce: A, subscribed on elevation, receives `:<srv> EVENT A …`.
    try writeAllFd(fd_a, "EVENT BROADCAST :hello opers\r\n");
    try recvUntil(&a, " EVENT ", 200);
    try recvUntil(&a, "hello opers", 200);
    // A negotiated `setname`, not `message-tags`, so its event note must arrive
    // WITHOUT the @event-* tag prefix (the cap-gated plain-delivery branch).
    try std.testing.expect(std.mem.indexOf(u8, a.written(), "@event-category") == null);
    // REHASH now permitted (382).
    a.reset();
    try writeAllFd(fd_a, "REHASH\r\n");
    try recvUntil(&a, " 382 A ", 200);
    // MESH ADMISSION exposes MeshPass posture without leaking admission bytes.
    a.reset();
    try writeAllFd(fd_a, "MESH ADMISSION\r\n");
    try recvUntil(&a, "NOTICE A :admission mode=", 200);
    try recvUntil(&a, "token_present=false", 200);

    // INFO (371), USERS (392), LINKS (364), MAP (015).
    a.reset();
    try writeAllFd(fd_a, "INFO\r\n");
    try recvUntil(&a, " 371 A ", 200);
    a.reset();
    try writeAllFd(fd_a, "DIRECTORY\r\n");
    try recvUntil(&a, " 373 A :Orochi discovery directory\r\n", 200);
    try recvUntil(&a, " 371 A :listed=", 200);
    try recvUntil(&a, " 374 A :End of /DIRECTORY\r\n", 200);
    a.reset();
    try writeAllFd(fd_a, "USERS\r\n");
    try recvUntil(&a, " 392 A ", 200);
    a.reset();
    try writeAllFd(fd_a, "LINKS\r\n");
    try recvUntil(&a, " 364 A ", 200);
    a.reset();
    try writeAllFd(fd_a, "MAP\r\n");
    try recvUntil(&a, " 015 A ", 200);
    // STATS u -> uptime (242) + end (219).
    a.reset();
    try writeAllFd(fd_a, "STATS u\r\n");
    try recvUntil(&a, " 242 A ", 200);
    try recvUntil(&a, " 219 A u ", 200);

    // Bot mode: B sets +B on itself -> MODE echo; WHOIS B shows 335.
    b.reset();
    try writeAllFd(fd_b, "MODE B +B\r\n");
    try recvUntil(&b, "MODE B +B", 200);
    a.reset();
    try writeAllFd(fd_a, "WHOIS B\r\n");
    try recvUntil(&a, " 335 A B ", 200);

    // KILL: oper A kills B -> B receives a KILL line then is disconnected.
    a.reset();
    b.reset();
    try writeAllFd(fd_a, "KILL B :spam\r\n");
    try recvUntil(&b, "KILL B :spam\r\n", 200);
    // Oper A (subscribed) also sees the KILL as an Event Spine event
    // (`:<srv> EVENT A <killer> killed <target> (<reason>)`).
    try recvUntil(&a, "killed B ", 200);

    // Operator UI form: EVENT STATS JSON returns a stable machine-readable
    // object with all category/severity keys present.
    a.reset();
    try writeAllFd(fd_a, "EVENT STATS JSON\r\n");
    try recvUntil(&a, "\"total\":", 200);
    try std.testing.expect(std.mem.indexOf(u8, a.written(), "\"history_depth\":") != null);
    try std.testing.expect(std.mem.indexOf(u8, a.written(), "\"categories\":{\"connect\":") != null);
    try std.testing.expect(std.mem.indexOf(u8, a.written(), "\"announce\":") != null);
    try std.testing.expect(std.mem.indexOf(u8, a.written(), "\"kill\":") != null);
    try std.testing.expect(std.mem.indexOf(u8, a.written(), "\"severities\":{\"debug\":") != null);
    try std.testing.expect(std.mem.indexOf(u8, a.written(), "\"critical\":") != null);
    try std.testing.expect(std.mem.indexOf(u8, a.written(), "\"operator_surfaces\":{") != null);
    try std.testing.expect(std.mem.indexOf(u8, a.written(), "\"event_replay_json\":true") != null);
    try std.testing.expect(std.mem.indexOf(u8, a.written(), "\"event_stats_json\":true") != null);
    try std.testing.expect(std.mem.indexOf(u8, a.written(), "\"audit_event_spine\":true") != null);
    try std.testing.expect(std.mem.indexOf(u8, a.written(), "\"audit_json\":true") != null);
    try std.testing.expect(std.mem.indexOf(u8, a.written(), "\"audit_proof_json\":true") != null);
    try std.testing.expect(std.mem.indexOf(u8, a.written(), "\"proofmark\":true") != null);
    try std.testing.expect(std.mem.indexOf(u8, a.written(), "\"admission_security_events\":true") != null);
    try std.testing.expect(std.mem.indexOf(u8, a.written(), "\"security_reputation_events\":true") != null);
    try std.testing.expect(std.mem.indexOf(u8, a.written(), "\"security_throttle_events\":true") != null);
    try std.testing.expect(std.mem.indexOf(u8, a.written(), "\"security_clone_events\":true") != null);

    // Operator UI form: EVENT REPLAY JSON streams bounded JSON notices for
    // history without scraping the prose replay format.
    a.reset();
    try writeAllFd(fd_a, "EVENT REPLAY JSON ALL 5\r\n");
    try recvUntil(&a, "\"type\":\"event-replay\"", 200);
    try recvUntil(&a, "\"type\":\"event\"", 200);
    try std.testing.expect(std.mem.indexOf(u8, a.written(), "\"category\":") != null);
    try std.testing.expect(std.mem.indexOf(u8, a.written(), "\"category_code\":") != null);
    try std.testing.expect(std.mem.indexOf(u8, a.written(), "\"severity\":") != null);
    try std.testing.expect(std.mem.indexOf(u8, a.written(), "\"origin\":") != null);
    try std.testing.expect(std.mem.indexOf(u8, a.written(), "\"message\":") != null);
    try recvUntil(&a, "\"type\":\"event-replay-end\"", 200);
}

test "threaded server: SETNAME self echo requires setname cap" {
    var server = Server.init(std.testing.allocator, .{ .host = "127.0.0.1", .port = 0 }) catch |err| switch (err) {
        error.Unsupported, error.PermissionDenied, error.SocketUnavailable => return error.SkipZigTest,
        else => return err,
    };
    defer server.deinit();
    const port = try server.boundPort();

    var run = std.atomic.Value(bool).init(true);
    var thr = try std.Thread.spawn(.{}, Server.runThreaded, .{ &server, &run });
    defer {
        run.store(false, .release);
        if (connectLoopback(port)) |wfd| closeFd(wfd) else |_| {}
        thr.join();
    }

    const fd_a = connectLoopback(port) catch return error.SkipZigTest;
    defer closeFd(fd_a);
    var a = LiveClient{ .fd = fd_a };
    try writeAllFd(fd_a, "NICK A\r\nUSER alice 0 * :Alice\r\n");
    try recvUntil(&a, " 001 A ", 200);

    a.reset();
    try writeAllFd(fd_a, "SETNAME :No Echo\r\nPING :setname-gate\r\n");
    try recvUntil(&a, "PONG orochi.local :setname-gate", 200);
    try std.testing.expect(std.mem.indexOf(u8, a.written(), "SETNAME :No Echo\r\n") == null);
}

test "threaded server: channel-mode enforcement +k/+l/+b/+i end-to-end" {
    var server = Server.init(std.testing.allocator, .{ .host = "127.0.0.1", .port = 0 }) catch |err| switch (err) {
        error.Unsupported, error.PermissionDenied, error.SocketUnavailable => return error.SkipZigTest,
        else => return err,
    };
    defer server.deinit();
    const port = try server.boundPort();

    var run = std.atomic.Value(bool).init(true);
    var thr = try std.Thread.spawn(.{}, Server.runThreaded, .{ &server, &run });
    defer {
        run.store(false, .release);
        if (connectLoopback(port)) |wfd| closeFd(wfd) else |_| {}
        thr.join();
    }

    const fd_a = connectLoopback(port) catch return error.SkipZigTest;
    defer closeFd(fd_a);
    const fd_b = connectLoopback(port) catch return error.SkipZigTest;
    defer closeFd(fd_b);
    var a = LiveClient{ .fd = fd_a };
    var b = LiveClient{ .fd = fd_b };

    try writeAllFd(fd_a, "NICK A\r\nUSER alice 0 * :Alice\r\n");
    try writeAllFd(fd_b, "NICK B\r\nUSER bob 0 * :Bob\r\n");
    try recvUntil(&a, " 001 A ", 200);
    try recvUntil(&b, " 001 B ", 200);

    // A founds #c, then sets a key.
    a.reset();
    try writeAllFd(fd_a, "JOIN #c\r\n");
    try recvUntil(&a, " 366 A #c ", 200);
    a.reset();
    try writeAllFd(fd_a, "MODE #c +k sesame\r\n");
    try recvUntil(&a, "MODE #c +k sesame", 200);

    // B joins without key -> 475; with the right key -> success.
    b.reset();
    try writeAllFd(fd_b, "JOIN #c\r\n");
    try recvUntil(&b, " 475 B #c ", 200);
    b.reset();
    try writeAllFd(fd_b, "JOIN #c sesame\r\n");
    try recvUntil(&b, " 366 B #c ", 200);

    // +l limit: A founds #l, sets +l 1 (A is the only member) -> B is full out.
    a.reset();
    try writeAllFd(fd_a, "JOIN #l\r\n");
    try recvUntil(&a, " 366 A #l ", 200);
    a.reset();
    try writeAllFd(fd_a, "MODE #l +l 1\r\n");
    try recvUntil(&a, "MODE #l +l 1", 200);
    b.reset();
    try writeAllFd(fd_b, "JOIN #l\r\n");
    try recvUntil(&b, " 471 B #l ", 200);

    // +b ban: A bans B, B parts and is refused re-entry (474, even with key).
    a.reset();
    try writeAllFd(fd_a, "MODE #c +b B!*@*\r\n");
    try recvUntil(&a, "MODE #c +b B!*@*", 200);
    b.reset();
    try writeAllFd(fd_b, "PART #c\r\n");
    try recvUntil(&b, "PART #c", 200);
    b.reset();
    try writeAllFd(fd_b, "JOIN #c sesame\r\n");
    try recvUntil(&b, " 474 B #c ", 200);

    // INVITE does not bypass +b: the invite is delivered, but JOIN is still denied.
    a.reset();
    try writeAllFd(fd_a, "INVITE B #c\r\n");
    try recvUntil(&a, " 341 A B #c", 200);
    b.reset();
    try writeAllFd(fd_b, "JOIN #c sesame\r\n");
    try recvUntil(&b, " 474 B #c ", 200);

    // Ban-list query: 367 entry + 368 end.
    a.reset();
    try writeAllFd(fd_a, "MODE #c b\r\n");
    try recvUntil(&a, " 367 A #c B!*@*", 200);
    try recvUntil(&a, " 368 A #c ", 200);

    // Clear the ban and let B back in for the later shared-channel QUIT/WHOWAS
    // assertions; invite bypass was already checked above.
    a.reset();
    try writeAllFd(fd_a, "MODE #c -b B!*@*\r\n");
    try recvUntil(&a, "MODE #c -b B!*@*", 200);
    b.reset();
    try writeAllFd(fd_b, "JOIN #c sesame\r\n");
    try recvUntil(&b, " 366 B #c ", 200);

    // KNOCK: A founds a fresh +i channel #i (B is not a member); B knocks ->
    // A (op) gets 710, B gets 711. B stays in #c for the WHOWAS step below.
    a.reset();
    try writeAllFd(fd_a, "JOIN #i\r\n");
    try recvUntil(&a, " 366 A #i ", 200);
    a.reset();
    try writeAllFd(fd_a, "MODE #i +i\r\n");
    try recvUntil(&a, "MODE #i +i", 200);
    a.reset();
    b.reset();
    try writeAllFd(fd_b, "KNOCK #i :let me in\r\n");
    try recvUntil(&a, " 710 A #i ", 200);
    try recvUntil(&b, " 711 B #i ", 200);

    // WHOWAS: B quits (A shares #c so sees the QUIT, after the whowas record is
    // taken), then A WHOWAS B -> 314 user line + 369 end.
    a.reset();
    try writeAllFd(fd_b, "QUIT :gone\r\n");
    try recvUntil(&a, "QUIT :gone", 200);
    a.reset();
    try writeAllFd(fd_a, "WHOWAS B\r\n");
    try recvUntil(&a, " 314 A B ", 200);
    try recvUntil(&a, " 369 A B ", 200);
}

test "threaded server: MODE +k enforces configured KEYLEN (reject over-long, accept at boundary)" {
    // keylen = 8: a 10-byte key is rejected (channel stays unkeyed); an 8-byte
    // key at the boundary is accepted. Enforce-then-advertise: the same cap that
    // rides in ISUPPORT KEYLEN is what the +k handler refuses to exceed.
    var server = Server.init(std.testing.allocator, .{ .host = "127.0.0.1", .port = 0, .keylen = 8 }) catch |err| switch (err) {
        error.Unsupported, error.PermissionDenied, error.SocketUnavailable => return error.SkipZigTest,
        else => return err,
    };
    defer server.deinit();
    const port = try server.boundPort();

    var run = std.atomic.Value(bool).init(true);
    var thr = try std.Thread.spawn(.{}, Server.runThreaded, .{ &server, &run });
    defer {
        run.store(false, .release);
        if (connectLoopback(port)) |wfd| closeFd(wfd) else |_| {}
        thr.join();
    }

    const fd_a = connectLoopback(port) catch return error.SkipZigTest;
    defer closeFd(fd_a);
    const fd_b = connectLoopback(port) catch return error.SkipZigTest;
    defer closeFd(fd_b);
    var a = LiveClient{ .fd = fd_a };
    var b = LiveClient{ .fd = fd_b };

    try writeAllFd(fd_a, "NICK A\r\nUSER alice 0 * :Alice\r\n");
    try writeAllFd(fd_b, "NICK B\r\nUSER bob 0 * :Bob\r\n");
    try recvUntil(&a, " 001 A ", 200);
    try recvUntil(&b, " 001 B ", 200);

    // Over-long key (10 > 8) is rejected: #k1 stays unkeyed, so B joins keyless.
    a.reset();
    try writeAllFd(fd_a, "JOIN #k1\r\n");
    try recvUntil(&a, " 366 A #k1 ", 200);
    a.reset();
    try writeAllFd(fd_a, "MODE #k1 +k toolongkey\r\n");
    a.reset();
    try writeAllFd(fd_a, "MODE #k1\r\n");
    try recvUntil(&a, " 324 A #k1 ", 200);
    try std.testing.expect(std.mem.indexOf(u8, a.written(), "toolongkey") == null);
    b.reset();
    try writeAllFd(fd_b, "JOIN #k1\r\n");
    try recvUntil(&b, " 366 B #k1 ", 200);

    // Boundary key (exactly 8) is accepted and echoed; a keyless join is refused.
    a.reset();
    try writeAllFd(fd_a, "JOIN #k2\r\n");
    try recvUntil(&a, " 366 A #k2 ", 200);
    a.reset();
    try writeAllFd(fd_a, "MODE #k2 +k pw8chars\r\n");
    try recvUntil(&a, "MODE #k2 +k pw8chars", 200);
    b.reset();
    try writeAllFd(fd_b, "JOIN #k2\r\n");
    try recvUntil(&b, " 475 B #k2 ", 200);
}

test "threaded server: JOIN INVITE NAMES MODE and TOPIC RFC parity regressions" {
    var server = Server.init(std.testing.allocator, .{ .host = "127.0.0.1", .port = 0 }) catch |err| switch (err) {
        error.Unsupported, error.PermissionDenied, error.SocketUnavailable => return error.SkipZigTest,
        else => return err,
    };
    defer server.deinit();
    const port = try server.boundPort();

    var run = std.atomic.Value(bool).init(true);
    var thr = try std.Thread.spawn(.{}, Server.runThreaded, .{ &server, &run });
    defer {
        run.store(false, .release);
        if (connectLoopback(port)) |wfd| closeFd(wfd) else |_| {}
        thr.join();
    }

    const fd_a = connectLoopback(port) catch return error.SkipZigTest;
    defer closeFd(fd_a);
    const fd_b = connectLoopback(port) catch return error.SkipZigTest;
    defer closeFd(fd_b);
    var a = LiveClient{ .fd = fd_a };
    var b = LiveClient{ .fd = fd_b };

    try writeAllFd(fd_a, "NICK A\r\nUSER alice 0 * :Alice\r\n");
    try writeAllFd(fd_b, "NICK B\r\nUSER bob 0 * :Bob\r\n");
    try recvUntil(&a, " 001 A ", 200);
    try recvUntil(&b, " 001 B ", 200);

    // Fresh channels get +nt immediately, echoed to the creator and reflected in
    // MODE query with a creation-time 329.
    a.reset();
    try writeAllFd(fd_a, "JOIN #nt\r\n");
    try recvUntil(&a, "MODE #nt +nt", 200);
    try recvUntil(&a, " 366 A #nt ", 200);
    a.reset();
    try writeAllFd(fd_a, "MODE #nt\r\n");
    try recvUntil(&a, " 324 A #nt +nt ", 200);
    try recvUntil(&a, " 329 A #nt ", 200);
    try expectDigitAfter(a.written(), " 329 A #nt ");

    // Ban-list rows include setter mask and set-at timestamp.
    a.reset();
    try writeAllFd(fd_a, "MODE #nt +b Bad!*@*\r\n");
    try recvUntil(&a, "MODE #nt +b Bad!*@*", 200);
    a.reset();
    try writeAllFd(fd_a, "MODE #nt b\r\n");
    try recvUntil(&a, " 367 A #nt Bad!*@* A!alice@localhost ", 200);
    try expectDigitAfter(a.written(), " 367 A #nt Bad!*@* A!alice@localhost ");
    try recvUntil(&a, " 368 A #nt ", 200);

    // Topic queries emit both 332 and 333 with setter and Unix seconds.
    a.reset();
    try writeAllFd(fd_a, "TOPIC #nt :hello world\r\n");
    try recvUntil(&a, "TOPIC #nt :hello world", 200);
    a.reset();
    try writeAllFd(fd_a, "TOPIC #nt\r\n");
    try recvUntil(&a, " 332 A #nt :hello world", 200);
    try recvUntil(&a, " 333 A #nt A!alice@localhost ", 200);
    try expectDigitAfter(a.written(), " 333 A #nt A!alice@localhost ");

    // Bare NAMES lists visible channels; a valid absent channel returns only 366.
    a.reset();
    try writeAllFd(fd_a, "NAMES\r\n");
    try recvUntil(&a, " 353 A = #nt ", 200);
    a.reset();
    try writeAllFd(fd_a, "NAMES #absent\r\n");
    try recvUntil(&a, " 366 A #absent ", 200);
    try a.readAvailable();
    try std.testing.expect(std.mem.indexOf(u8, a.written(), " 403 A #absent ") == null);

    // INVITE resolves the target nick first, even when the channel is absent.
    a.reset();
    try writeAllFd(fd_a, "INVITE Ghost #ghost\r\n");
    try recvUntil(&a, " 401 A Ghost ", 200);
    try a.readAvailable();
    try std.testing.expect(std.mem.indexOf(u8, a.written(), " 403 A #ghost ") == null);

    // INVITE is delivered but does not bypass +b.
    a.reset();
    try writeAllFd(fd_a, "JOIN #ban\r\n");
    try recvUntil(&a, " 366 A #ban ", 200);
    a.reset();
    try writeAllFd(fd_a, "MODE #ban +b B!*@*\r\n");
    try recvUntil(&a, "MODE #ban +b B!*@*", 200);
    a.reset();
    try writeAllFd(fd_a, "INVITE B #ban\r\n");
    try recvUntil(&a, " 341 A B #ban", 200);
    b.reset();
    try writeAllFd(fd_b, "JOIN #ban\r\n");
    try recvUntil(&b, " 474 B #ban ", 200);

    // Invites on ordinary channels are not persisted for later +i joins.
    a.reset();
    try writeAllFd(fd_a, "JOIN #plain\r\n");
    try recvUntil(&a, " 366 A #plain ", 200);
    a.reset();
    try writeAllFd(fd_a, "INVITE B #plain\r\n");
    try recvUntil(&a, " 341 A B #plain", 200);
    a.reset();
    try writeAllFd(fd_a, "MODE #plain +i\r\n");
    try recvUntil(&a, "MODE #plain +i", 200);
    b.reset();
    try writeAllFd(fd_b, "JOIN #plain\r\n");
    try recvUntil(&b, " 473 B #plain ", 200);

    // An invite on a +i/+l channel bypasses invite-only and full-channel gates.
    a.reset();
    try writeAllFd(fd_a, "JOIN #limit\r\n");
    try recvUntil(&a, " 366 A #limit ", 200);
    a.reset();
    try writeAllFd(fd_a, "MODE #limit +il 1\r\n");
    try recvUntil(&a, "MODE #limit +il 1", 200);
    a.reset();
    try writeAllFd(fd_a, "INVITE B #limit\r\n");
    try recvUntil(&a, " 341 A B #limit", 200);
    b.reset();
    try writeAllFd(fd_b, "JOIN #limit\r\n");
    try recvUntil(&b, " 366 B #limit ", 200);
}

test "threaded server: IRCv3 server-time tag on PRIVMSG for cap holders" {
    var server = Server.init(std.testing.allocator, .{ .host = "127.0.0.1", .port = 0 }) catch |err| switch (err) {
        error.Unsupported, error.PermissionDenied, error.SocketUnavailable => return error.SkipZigTest,
        else => return err,
    };
    defer server.deinit();
    const port = try server.boundPort();

    var run = std.atomic.Value(bool).init(true);
    var thr = try std.Thread.spawn(.{}, Server.runThreaded, .{ &server, &run });
    defer {
        run.store(false, .release);
        if (connectLoopback(port)) |wfd| closeFd(wfd) else |_| {}
        thr.join();
    }

    const fd_a = connectLoopback(port) catch return error.SkipZigTest;
    defer closeFd(fd_a);
    const fd_b = connectLoopback(port) catch return error.SkipZigTest;
    defer closeFd(fd_b);
    var a = LiveClient{ .fd = fd_a };
    var b = LiveClient{ .fd = fd_b };

    // A negotiates server-time; B does not.
    try writeAllFd(fd_a, "CAP REQ :server-time\r\n");
    try recvUntil(&a, "ACK :server-time", 200);
    try writeAllFd(fd_a, "NICK A\r\nUSER alice 0 * :Alice\r\nCAP END\r\n");
    try recvUntil(&a, " 001 A ", 200);
    try writeAllFd(fd_b, "NICK B\r\nUSER bob 0 * :Bob\r\n");
    try recvUntil(&b, " 001 B ", 200);

    try writeAllFd(fd_a, "JOIN #t\r\n");
    try recvUntil(&a, " 366 A #t ", 200);
    try writeAllFd(fd_b, "JOIN #t\r\n");
    try recvUntil(&b, " 366 B #t ", 200);

    // B messages the channel; A (cap holder) sees a @time= tag before the prefix.
    a.reset();
    try writeAllFd(fd_b, "PRIVMSG #t :hello\r\n");
    try recvUntil(&a, "@time=", 200);
    try recvUntil(&a, ":B!bob@localhost PRIVMSG #t :hello\r\n", 200);
}

