    const fd_ok = connectLoopback(port) catch return error.SkipZigTest;
    defer closeFd(fd_ok);
    var ok = LiveClient{ .fd = fd_ok };
    try writeAllFd(fd_ok, "NICK Safe\r\nUSER safe 0 * :Safe\r\n");
    try recvUntil(&ok, " 001 Safe ", 400);
}

