    try writeAllFd(fd_a, "MODE #aud +x\r\n");
    try recvUntil(a, "MODE #aud +x", 200);
    // C (regular) sees the founder A and itself, but NOT the other regular B.
    c.reset();
    try writeAllFd(fd_c, "NAMES #aud\r\n");
