    try std.testing.expect(std.mem.indexOf(u8, c.written(), "C") != null);
    try std.testing.expect(std.mem.indexOf(u8, c.written(), "!A") != null);
    try std.testing.expect(std.mem.indexOf(u8, c.written(), "B") == null);
}

