test "threaded server: media user modes block transmit and hide automatic presence" {
    var cfg = multiOperTestConfig(0);
    cfg.media_reactions_max_token_bytes = 4;
    var server = Server.init(std.testing.allocator, cfg) catch |err| switch (err) {
        error.Unsupported, error.PermissionDenied, error.SocketUnavailable => return error.SkipZigTest,
        else => return err,
    };
    defer server.deinit();
    const port = try server.boundPort();
    var run = std.atomic.Value(bool).init(true);
    var thr = try std.Thread.spawn(.{}, Server.runThreaded, .{ &server, &run });
    defer {
        run.store(false, .release);
        if (connectLoopback(port)) |wfd| closeFd(wfd) else |_| {}
        thr.join();
    }

    const fd_a = connectLoopback(port) catch return error.SkipZigTest;
    defer closeFd(fd_a);
    const fd_b = connectLoopback(port) catch return error.SkipZigTest;
    defer closeFd(fd_b);
    var a = LiveClient{ .fd = fd_a };
    var b = LiveClient{ .fd = fd_b };

    try saslPlainPrelude(fd_a, "admin", "orochi");
    try writeAllFd(fd_a, "NICK A\r\nUSER alice 0 * :Alice\r\n");
    try recvUntil(&a, " 381 A ", 200);
    try writeAllFd(fd_b, "CAP REQ :standard-replies\r\nNICK B\r\nUSER bob 0 * :Bob\r\nCAP END\r\n");
    try recvUntil(&b, " 001 B ", 200);
    try writeAllFd(fd_a, "JOIN #media\r\n");
    try recvUntil(&a, " 366 A #media ", 200);
    try writeAllFd(fd_b, "JOIN #media\r\n");
    try recvUntil(&b, " 366 B #media ", 200);

    b.reset();
    try writeAllFd(fd_a, "MODE B +M\r\n");
    try recvUntil(&b, "MODE B +M", 200);
    b.reset();
    try writeAllFd(fd_b, "MEDIA JOIN #media voice\r\n");
    try recvUntil(&b, "FAIL MEDIA TX_DENIED", 200);

    b.reset();
    try writeAllFd(fd_a, "MODE B -M\r\n");
    try recvUntil(&b, "MODE B -M", 200);
    try writeAllFd(fd_b, "MODE B +P\r\n");
    try recvUntil(&b, "MODE B +P", 200);
    a.reset();
    try writeAllFd(fd_b, "MEDIA JOIN #media voice\r\n");
    try writeAllFd(fd_a, "PING :media-private\r\n");
    try recvUntil(&a, "PONG orochi.local :media-private", 200);
    try std.testing.expect(std.mem.indexOf(u8, a.written(), "MEDIA JOIN #media B voice") == null);

    a.reset();
    try writeAllFd(fd_a, "MEDIA ROSTER #media\r\n");
    try recvUntil(&a, "EVENT A MEDIA ROSTER #media B voice", 200);
    b.reset();
    try writeAllFd(fd_b, "MEDIA REACT #media abcde\r\n");
    try recvUntil(&b, "FAIL MEDIA INVALID_REACTION", 200);

    b.reset();
    try writeAllFd(fd_a, "MODE B +M\r\n");
    try recvUntil(&b, "MODE B +M", 200);
    b.reset();
    try writeAllFd(fd_b, "MEDIA SPEAKING #media voice on\r\n");
    try recvUntil(&b, "FAIL MEDIA TX_DENIED", 200);
    b.reset();
    try writeAllFd(fd_b, "MODE B\r\n");
    try recvUntil(&b, " 221 B :+", 200);
    try std.testing.expect(std.mem.indexOfScalar(u8, b.written(), 'M') != null);
    try std.testing.expect(std.mem.indexOfScalar(u8, b.written(), 'P') != null);
}

test "threaded server: MEDIA OFFER RFC 8122 DTLS signaling (fingerprint/setup vs legacy srtp)" {
    var cfg = multiOperTestConfig(0);
    cfg.media_enabled = true;
    cfg.media_dtls_srtp = true; // opt-in DTLS-SRTP keying on
    var server = Server.init(std.testing.allocator, cfg) catch |err| switch (err) {
        error.Unsupported, error.PermissionDenied, error.SocketUnavailable => return error.SkipZigTest,
        else => return err,
    };
    defer server.deinit();
    server.start(); // bring up the media plane + DTLS terminator
    // Skip in sandboxes where the media UDP plane cannot bind (no terminator).
    if (server.media_plane.port == 0) return error.SkipZigTest;
    const port = try server.boundPort();
    var run = std.atomic.Value(bool).init(true);
    var thr = try std.Thread.spawn(.{}, Server.runThreaded, .{ &server, &run });
    defer {
        run.store(false, .release);
        if (connectLoopback(port)) |wfd| closeFd(wfd) else |_| {}
        thr.join();
    }

    const fd_a = connectLoopback(port) catch return error.SkipZigTest;
    defer closeFd(fd_a);
    var a = LiveClient{ .fd = fd_a };
    try saslPlainPrelude(fd_a, "admin", "orochi");
    try writeAllFd(fd_a, "NICK A\r\nUSER alice 0 * :Alice\r\n");
    try recvUntil(&a, " 381 A ", 200);
    try writeAllFd(fd_a, "JOIN #media\r\n");
    try recvUntil(&a, " 366 A #media ", 200);

    // Build a well-formed sha-256 fingerprint token (colon-joined single token).
    var fpbuf: [128]u8 = undefined;
    const fpline = try dtls_fingerprint_mod.format(.sha256, "peer client certificate", &fpbuf);
    const peer_hex = fpline["sha-256 ".len..];

    // (a) OFFER requesting DTLS keying → TRANSPORT carries fingerprint=sha-256 …
    //     + setup=passive and NO srtp= group key.
    a.reset();
    var offer_buf: [256]u8 = undefined;
    const offer = try std.fmt.bufPrint(&offer_buf, "MEDIA OFFER #media kaguravox transport=webrtc fingerprint=sha-256:{s} setup=active\r\n", .{peer_hex});
    try writeAllFd(fd_a, offer);
    try recvUntil(&a, "EVENT A MEDIA TRANSPORT #media", 200);
    // Drain a beat so the whole TRANSPORT line is buffered before we inspect it.
    try recvUntil(&a, "setup=passive", 200);
    try std.testing.expect(std.mem.indexOf(u8, a.written(), "fingerprint=sha-256 ") != null);
    try std.testing.expect(std.mem.indexOf(u8, a.written(), "setup=passive") != null);
    try std.testing.expect(std.mem.indexOf(u8, a.written(), "srtp=") == null);

    // (b) OFFER WITHOUT a fingerprint (feature on, not requested) → byte-identical
    //     legacy srtp= group-key reply, no fingerprint/setup.
    a.reset();
    try writeAllFd(fd_a, "MEDIA OFFER #media kaguravox transport=webrtc\r\n");
    try recvUntil(&a, "EVENT A MEDIA TRANSPORT #media", 200);
    try recvUntil(&a, "srtp=", 200);
    try std.testing.expect(std.mem.indexOf(u8, a.written(), "srtp=") != null);
    try std.testing.expect(std.mem.indexOf(u8, a.written(), "fingerprint=") == null);
    try std.testing.expect(std.mem.indexOf(u8, a.written(), "setup=") == null);

    // (e) Malformed fingerprint → FAIL MEDIA BAD_FINGERPRINT, never a trap.
    a.reset();
    try writeAllFd(fd_a, "MEDIA OFFER #media kaguravox transport=webrtc fingerprint=sha-256:00:11:22 setup=active\r\n");
    try recvUntil(&a, "FAIL MEDIA BAD_FINGERPRINT", 200);
}

test "threaded server: MEDIA OFFER with DTLS off is byte-identical + fails closed on a fingerprint request" {
    var cfg = multiOperTestConfig(0);
    cfg.media_enabled = true;
    cfg.media_dtls_srtp = false; // DTLS-SRTP disabled (default)
    var server = Server.init(std.testing.allocator, cfg) catch |err| switch (err) {
        error.Unsupported, error.PermissionDenied, error.SocketUnavailable => return error.SkipZigTest,
        else => return err,
    };
    defer server.deinit();
    const port = try server.boundPort();
    var run = std.atomic.Value(bool).init(true);
    var thr = try std.Thread.spawn(.{}, Server.runThreaded, .{ &server, &run });
    defer {
        run.store(false, .release);
        if (connectLoopback(port)) |wfd| closeFd(wfd) else |_| {}
        thr.join();
    }

    const fd_a = connectLoopback(port) catch return error.SkipZigTest;
    defer closeFd(fd_a);
    var a = LiveClient{ .fd = fd_a };
    try saslPlainPrelude(fd_a, "admin", "orochi");
    try writeAllFd(fd_a, "NICK A\r\nUSER alice 0 * :Alice\r\n");
    try recvUntil(&a, " 381 A ", 200);
    try writeAllFd(fd_a, "JOIN #media\r\n");
    try recvUntil(&a, " 366 A #media ", 200);

    // With the feature off, a plain OFFER still ships the legacy srtp= group key.
    a.reset();
    try writeAllFd(fd_a, "MEDIA OFFER #media kaguravox transport=webrtc\r\n");
    try recvUntil(&a, "EVENT A MEDIA TRANSPORT #media", 200);
    try recvUntil(&a, "srtp=", 200);
    try std.testing.expect(std.mem.indexOf(u8, a.written(), "srtp=") != null);
    try std.testing.expect(std.mem.indexOf(u8, a.written(), "fingerprint=") == null);

    // A DTLS keying request when the server has it off fails closed (no media,
    // no leaked group key).
    var fpbuf: [128]u8 = undefined;
    const fpline = try dtls_fingerprint_mod.format(.sha256, "peer cert", &fpbuf);
    a.reset();
    var offer_buf: [256]u8 = undefined;
    const offer = try std.fmt.bufPrint(&offer_buf, "MEDIA OFFER #media kaguravox transport=webrtc fingerprint=sha-256:{s} setup=active\r\n", .{fpline["sha-256 ".len..]});
    try writeAllFd(fd_a, offer);
    try recvUntil(&a, "FAIL MEDIA DTLS_UNAVAILABLE", 200);
    try std.testing.expect(std.mem.indexOf(u8, a.written(), "srtp=") == null);
}

test "threaded server: MEDIA ANSWER provisions transport and native leg" {
    var cfg = multiOperTestConfig(0);
    cfg.media_enabled = true;
    var server = Server.init(std.testing.allocator, cfg) catch |err| switch (err) {
        error.Unsupported, error.PermissionDenied, error.SocketUnavailable => return error.SkipZigTest,
        else => return err,
    };
    defer server.deinit();
    server.start();
    if (server.media_plane.port == 0 or server.native_media.port == 0) return error.SkipZigTest;
    const port = try server.boundPort();
    var run = std.atomic.Value(bool).init(true);
    var thr = try std.Thread.spawn(.{}, Server.runThreaded, .{ &server, &run });
    defer {
        run.store(false, .release);
        if (connectLoopback(port)) |wfd| closeFd(wfd) else |_| {}
        thr.join();
    }

    const fd_a = connectLoopback(port) catch return error.SkipZigTest;
    defer closeFd(fd_a);
    const fd_b = connectLoopback(port) catch return error.SkipZigTest;
    defer closeFd(fd_b);
    var a = LiveClient{ .fd = fd_a };
    var b = LiveClient{ .fd = fd_b };

    try writeAllFd(fd_a, "NICK A\r\nUSER alice 0 * :Alice\r\n");
    try writeAllFd(fd_b, "NICK B\r\nUSER bob 0 * :Bob\r\n");
    try recvUntil(&a, " 001 A ", 200);
    try recvUntil(&b, " 001 B ", 200);
    try writeAllFd(fd_a, "JOIN #media\r\n");
    try recvUntil(&a, " 366 A #media ", 200);
    try writeAllFd(fd_b, "JOIN #media\r\n");
    try recvUntil(&b, " 366 B #media ", 200);
    try writeAllFd(fd_a, "IRCX\r\n");
    try recvUntil(&a, " 800 A 1 0 ", 200);
    try writeAllFd(fd_b, "IRCX\r\n");
    try recvUntil(&b, " 800 B 1 0 ", 200);
    a.reset();
    try writeAllFd(fd_a, "EVENT ADD MEDIA #media\r\n");
    try recvUntil(&a, " 806 A MEDIA #media :Event added", 200);
    b.reset();
    try writeAllFd(fd_b, "EVENT ADD MEDIA #media\r\n");
    try recvUntil(&b, " 806 B MEDIA #media :Event added", 200);

    a.reset();
    b.reset();
    try writeAllFd(fd_a, "MEDIA JOIN #media voice\r\n");
    try recvUntil(&a, "MEDIA JOIN #media A voice", 200);
    try recvUntil(&b, "MEDIA JOIN #media A voice", 200);
    a.reset();
    b.reset();
    try writeAllFd(fd_b, "MEDIA JOIN #media voice\r\n");
    try recvUntil(&a, "MEDIA JOIN #media B voice", 200);
    try recvUntil(&b, "MEDIA JOIN #media B voice", 200);

    a.reset();
    b.reset();
    try writeAllFd(fd_a, "MEDIA OFFER #media kaguravox\r\n");
    try recvUntil(&b, "EVENT B MEDIA CAPS #media A codecs=kaguravox", 200);
    try recvUntil(&a, "EVENT A MEDIA OFFER-ACK #media", 200);
    try recvUntil(&a, "EVENT A MEDIA TRANSPORT #media", 200);
    try recvUntil(&a, "EVENT A MEDIA NATIVE #media", 200);

    b.reset();
    try writeAllFd(fd_b, "MEDIA ANSWER #media kaguravox,kaguravis transport=webrtc\r\n");
    try recvUntil(&a, "EVENT A MEDIA CAPS #media B codecs=kaguravox", 200);
    try recvUntil(&b, "EVENT B MEDIA KIND-DENIED #media kind=video reason=no_common_codec", 200);
    try recvUntil(&b, "EVENT B MEDIA ANSWER-ACK #media", 200);
    try recvUntil(&b, "EVENT B MEDIA TRANSPORT #media", 200);
    try recvUntil(&b, "srtp=", 200);
    try recvUntil(&b, "EVENT B MEDIA NATIVE #media", 200);
    try std.testing.expect(std.mem.indexOf(u8, b.written(), "ANSWER-ACK") != null);
    try std.testing.expect(std.mem.indexOf(u8, b.written(), "TRANSPORT #media ufrag=") != null);
    try std.testing.expect(std.mem.indexOf(u8, b.written(), "NATIVE #media candidate=") != null);

    b.reset();
    try writeAllFd(fd_b, "MEDIA ABR #media 1200 400 10 60 25\r\n");
    try recvUntil(&b, "EVENT B MEDIA ABR #media action=decrease", 200);
    try recvUntil(&b, "spatial<=0 temporal<=0", 200);

    b.reset();
    try writeAllFd(fd_b, "MEDIA ABR #media 0 400 10 60\r\n");
    try recvUntil(&b, "FAIL MEDIA BAD_ABR", 200);

    a.reset();
    try writeAllFd(fd_a, "MEDIA ROSTER #media\r\n");
    try recvUntil(&a, "MEDIA ROSTER-END #media", 200);
    try std.testing.expect(std.mem.indexOf(u8, a.written(), "EVENT A MEDIA ROSTER #media B voice main 0 0 - codecs=kaguravox,kaguravis fec=rs_block") != null);
}

