test "threaded server: LISTX filters on real channel SUBJECT from the PROP store" {
    // Proves the LISTX handler reads real channel data (not hardcoded blanks):
    // the S= subject filter must match a channel whose SUBJECT prop was set and
    // exclude one with no subject.
    var server = Server.init(std.testing.allocator, .{ .host = "127.0.0.1", .port = 0 }) catch |err| switch (err) {
        error.Unsupported, error.PermissionDenied, error.SocketUnavailable => return error.SkipZigTest,
        else => return err,
    };
    defer server.deinit();
    const port = try server.boundPort();
    var run = std.atomic.Value(bool).init(true);
    var thr = try std.Thread.spawn(.{}, Server.runThreaded, .{ &server, &run });
    defer {
        run.store(false, .release);
        if (connectLoopback(port)) |wfd| closeFd(wfd) else |_| {}
        thr.join();
    }
    const fd_a = connectLoopback(port) catch return error.SkipZigTest;
    defer closeFd(fd_a);
    const alloc = std.testing.allocator;
    const a = try alloc.create(LiveClient);
    defer alloc.destroy(a);
    a.* = .{ .fd = fd_a };
    try writeAllFd(fd_a, "NICK A\r\nUSER alice 0 * :Alice\r\n");
    try recvUntil(a, " 001 A ", 200);
    try writeAllFd(fd_a, "IRCX\r\n");
    try recvUntil(a, " 800 A 1 0 ", 200);
    try writeAllFd(fd_a, "JOIN #alpha\r\n");
    try recvUntil(a, " 366 A #alpha ", 200);
    try writeAllFd(fd_a, "JOIN #beta\r\n");
    try recvUntil(a, " 366 A #beta ", 200);
    a.reset();
    try writeAllFd(fd_a, "PROP #alpha SUBJECT :ziglang\r\n");
    try recvUntil(a, " 818 A #alpha ", 200);

    // S=zig* matches #alpha's real subject and excludes #beta (no subject).
    a.reset();
    try writeAllFd(fd_a, "LISTX S=zig*\r\n");
    try recvUntil(a, " 817 ", 200); // RPL_LISTXEND
    try std.testing.expect(std.mem.indexOf(u8, a.written(), "#alpha") != null);
    try std.testing.expect(std.mem.indexOf(u8, a.written(), "#beta") == null);
}

test "threaded server: LISTX inclusive >=N member-count threshold includes the boundary" {
    // Proves the inclusive member-count filter over the real wire: a single
    // client in #alpha makes it a 1-member channel, so `>=1` must include it
    // where the strict `>1` (which the daemon already supported) excludes it.
    var server = Server.init(std.testing.allocator, .{ .host = "127.0.0.1", .port = 0 }) catch |err| switch (err) {
        error.Unsupported, error.PermissionDenied, error.SocketUnavailable => return error.SkipZigTest,
        else => return err,
    };
    defer server.deinit();
    const port = try server.boundPort();
    var run = std.atomic.Value(bool).init(true);
    var thr = try std.Thread.spawn(.{}, Server.runThreaded, .{ &server, &run });
    defer {
        run.store(false, .release);
        if (connectLoopback(port)) |wfd| closeFd(wfd) else |_| {}
        thr.join();
    }
    const fd_a = connectLoopback(port) catch return error.SkipZigTest;
    defer closeFd(fd_a);
    const alloc = std.testing.allocator;
    const a = try alloc.create(LiveClient);
    defer alloc.destroy(a);
    a.* = .{ .fd = fd_a };
    try writeAllFd(fd_a, "NICK A\r\nUSER alice 0 * :Alice\r\n");
    try recvUntil(a, " 001 A ", 200);
    try writeAllFd(fd_a, "IRCX\r\n");
    try recvUntil(a, " 800 A 1 0 ", 200);
    try writeAllFd(fd_a, "JOIN #alpha\r\n");
    try recvUntil(a, " 366 A #alpha ", 200);

    // `>=1` includes the 1-member channel (inclusive boundary).
    a.reset();
    try writeAllFd(fd_a, "LISTX >=1\r\n");
    try recvUntil(a, " 817 ", 200); // RPL_LISTXEND
    try std.testing.expect(std.mem.indexOf(u8, a.written(), " 812 A #alpha ") != null);

    // Strict `>1` excludes it: the 812 entry must be absent.
    a.reset();
    try writeAllFd(fd_a, "LISTX >1\r\n");
    try recvUntil(a, " 817 ", 200);
    try std.testing.expect(std.mem.indexOf(u8, a.written(), " 812 A #alpha ") == null);
}

test "threaded server: LISTX emits PICS 813 after channel entries" {
    if (comptime builtin.os.tag == .linux) {
        var server = Server.init(std.testing.allocator, .{ .host = "127.0.0.1", .port = 0 }) catch |err| switch (err) {
            error.Unsupported, error.PermissionDenied, error.SocketUnavailable => return error.SkipZigTest,
            else => return err,
        };
        defer server.deinit();

        const port = try server.boundPort();
        var run = std.atomic.Value(bool).init(true);
        var thr = try std.Thread.spawn(.{}, Server.runThreaded, .{ &server, &run });
        defer {
            run.store(false, .release);
            if (connectLoopback(port)) |wfd| closeFd(wfd) else |_| {}
            thr.join();
        }

        const fd_a = connectLoopback(port) catch return error.SkipZigTest;
        defer closeFd(fd_a);
        var a = LiveClient{ .fd = fd_a };

        try writeAllFd(fd_a, "NICK A\r\nUSER alice 0 * :Alice\r\n");
        try recvUntil(&a, " 001 A ", 200);
        try writeAllFd(fd_a, "IRCX\r\n");
        try recvUntil(&a, " 800 A 1 0 ", 200);
        try writeAllFd(fd_a, "JOIN #alpha\r\n");
        try recvUntil(&a, " 366 A #alpha ", 200);
        // Seed PICS AFTER the creating JOIN: channel creation clearChannel-purges any
        // pre-seeded IRCX state, so seeding before would be wiped before LISTX.
        _ = try server.props.setProp(
            try ircx_prop_store.Entity.fromId("#alpha"),
            "PICS",
            "rated-safe",
            .{ .id = "server", .access = .server },
        );
        try writeAllFd(fd_a, "JOIN #beta\r\n");
        try recvUntil(&a, " 366 A #beta ", 200);

        a.reset();
        try writeAllFd(fd_a, "LISTX\r\n");
        try recvUntil(&a, " 817 ", 200);

        const written = a.written();
        const entry_index = std.mem.indexOf(u8, written, " 812 A #alpha ") orelse return error.TestExpectedEqual;
        const pics_index = std.mem.indexOf(u8, written, " 813 A #alpha :rated-safe\r\n") orelse return error.TestExpectedEqual;
        try std.testing.expect(pics_index > entry_index);
        try std.testing.expect(std.mem.indexOf(u8, written, " 813 A #beta ") == null);
    } else return error.SkipZigTest;
}

test "threaded server: PROP set/get gated by channel-op" {
    var server = Server.init(std.testing.allocator, .{ .host = "127.0.0.1", .port = 0 }) catch |err| switch (err) {
        error.Unsupported, error.PermissionDenied, error.SocketUnavailable => return error.SkipZigTest,
        else => return err,
    };
    defer server.deinit();
    const port = try server.boundPort();
    var run = std.atomic.Value(bool).init(true);
    var thr = try std.Thread.spawn(.{}, Server.runThreaded, .{ &server, &run });
    defer {
        run.store(false, .release);
        if (connectLoopback(port)) |wfd| closeFd(wfd) else |_| {}
        thr.join();
    }
    const fd_a = connectLoopback(port) catch return error.SkipZigTest;
    defer closeFd(fd_a);
    const fd_b = connectLoopback(port) catch return error.SkipZigTest;
    defer closeFd(fd_b);
    const alloc = std.testing.allocator;
    const a = try alloc.create(LiveClient);
    defer alloc.destroy(a);
    const b = try alloc.create(LiveClient);
    defer alloc.destroy(b);
    a.* = .{ .fd = fd_a };
    b.* = .{ .fd = fd_b };
    try writeAllFd(fd_a, "NICK A\r\nUSER alice 0 * :Alice\r\n");
    try writeAllFd(fd_b, "NICK B\r\nUSER bob 0 * :Bob\r\n");
    try recvUntil(a, " 001 A ", 200);
    try recvUntil(b, " 001 B ", 200);
    try writeAllFd(fd_a, "IRCX\r\n");
    try writeAllFd(fd_b, "IRCX\r\n");
    try recvUntil(a, " 800 A 1 0 ", 200);
    try recvUntil(b, " 800 B 1 0 ", 200);
    try writeAllFd(fd_a, "JOIN #p\r\n");
    try recvUntil(a, " 366 A #p ", 200);
    // Founder A sets a channel property and reads it back (818 + 819).
    a.reset();
    try writeAllFd(fd_a, "PROP #p SUBJECT :hello\r\n");
    try recvUntil(a, " 818 A #p ", 200);
    try recvUntil(a, " 819 A #p ", 200);
    a.reset();
    try writeAllFd(fd_a, "PROP #p SUBJECT\r\n");
    try recvUntil(a, " 818 A #p ", 200);
    // B, not on the channel, cannot set channel props (ERR_NOACCESS 913).
    b.reset();
    try writeAllFd(fd_b, "PROP #p SUBJECT :nope\r\n");
    try recvUntil(b, " 913 ", 200);
    // A sets a SECRET key; B (no write access) must not be able to read it back —
    // the GET returns only the 819 end with no 818/value leak.
    a.reset();
    try writeAllFd(fd_a, "PROP #p OWNERKEY :sekret\r\n");
    try recvUntil(a, " 818 A #p ", 200);
    b.reset();
    try writeAllFd(fd_b, "PROP #p OWNERKEY\r\n");
    try recvUntil(b, " 819 B #p ", 200);
    try std.testing.expect(std.mem.indexOf(u8, b.written(), "sekret") == null);
    try std.testing.expect(std.mem.indexOf(u8, b.written(), " 818 ") == null);

    // Verb forms: SET writes, GET can read computed built-ins, CLEAR removes
    // stored props while preserving client-safe replies.
    a.reset();
    try writeAllFd(fd_a, "PROP #p SET TOPIC :verb\r\n");
    try recvUntil(a, " 818 A #p TOPIC :verb", 200);
    try recvUntil(a, " 819 A #p ", 200);
    a.reset();
    try writeAllFd(fd_a, "PROP #p GET NAME\r\n");
    try recvUntil(a, " 818 A #p NAME :#p", 200);
    try recvUntil(a, " 819 A #p ", 200);
    a.reset();
    try writeAllFd(fd_a, "PROP #p CLEAR\r\n");
    try recvUntil(a, " 819 A #p ", 200);
    a.reset();
    try writeAllFd(fd_a, "PROP #p GET TOPIC\r\n");
    try recvUntil(a, " 819 A #p ", 200);
    try std.testing.expect(std.mem.indexOf(u8, a.written(), "verb") == null);
    try std.testing.expect(std.mem.indexOf(u8, a.written(), " 818 ") == null);
}

test "threaded server: PROP notify is IRCX-gated and per-tier secret" {
    var server = Server.init(std.testing.allocator, .{ .host = "127.0.0.1", .port = 0 }) catch |err| switch (err) {
        error.Unsupported, error.PermissionDenied, error.SocketUnavailable => return error.SkipZigTest,
        else => return err,
    };
    defer server.deinit();
    const port = try server.boundPort();
    var run = std.atomic.Value(bool).init(true);
    var thr = try std.Thread.spawn(.{}, Server.runThreaded, .{ &server, &run });
    defer {
        run.store(false, .release);
        if (connectLoopback(port)) |wfd| closeFd(wfd) else |_| {}
        thr.join();
    }
    const fd_a = connectLoopback(port) catch return error.SkipZigTest;
    defer closeFd(fd_a);
    const fd_b = connectLoopback(port) catch return error.SkipZigTest;
    defer closeFd(fd_b);
    const fd_c = connectLoopback(port) catch return error.SkipZigTest;
    defer closeFd(fd_c);
    const alloc = std.testing.allocator;
    const a = try alloc.create(LiveClient);
    defer alloc.destroy(a);
    const b = try alloc.create(LiveClient);
    defer alloc.destroy(b);
    const c = try alloc.create(LiveClient);
    defer alloc.destroy(c);
    a.* = .{ .fd = fd_a };
    b.* = .{ .fd = fd_b };
    c.* = .{ .fd = fd_c };
    // A founds #p (IRCX). B is an IRCX member; C is a member who never enables IRCX.
    try writeAllFd(fd_a, "NICK A\r\nUSER alice 0 * :Alice\r\n");
    try recvUntil(a, " 001 A ", 200);
    try writeAllFd(fd_a, "IRCX\r\nJOIN #p\r\n");
    try recvUntil(a, " 366 A #p ", 200);
    try writeAllFd(fd_b, "NICK B\r\nUSER bob 0 * :Bob\r\n");
    try recvUntil(b, " 001 B ", 200);
    try writeAllFd(fd_b, "IRCX\r\nJOIN #p\r\n");
    try recvUntil(b, " 366 B #p ", 200);
    try writeAllFd(fd_c, "NICK C\r\nUSER carol 0 * :Carol\r\n");
    try recvUntil(c, " 001 C ", 200);
    try writeAllFd(fd_c, "JOIN #p\r\n"); // no IRCX
    try recvUntil(c, " 366 C #p ", 200);
    b.reset();

    // Non-secret prop change reaches the IRCX member B.
    try writeAllFd(fd_a, "PROP #p SUBJECT :hello\r\n");
    try recvUntil(b, "PROP #p SUBJECT :hello", 200);
    b.reset();

    // A secret OWNERKEY change must NOT reach plain member B; a trailing
    // non-secret marker proves B's stream advanced past the secret set.
    try writeAllFd(fd_a, "PROP #p OWNERKEY :sekret\r\nPROP #p SUBJECT :marker\r\n");
    try recvUntil(b, "PROP #p SUBJECT :marker", 200);
    try std.testing.expect(std.mem.indexOf(u8, b.written(), "OWNERKEY") == null);
    try std.testing.expect(std.mem.indexOf(u8, b.written(), "sekret") == null);

    // Promote B to owner; now an OWNERKEY change reaches B (per-tier visibility).
    try writeAllFd(fd_a, "MODE #p +q B\r\n");
    try recvUntil(b, "+q B", 200);
    b.reset();
    try writeAllFd(fd_a, "PROP #p OWNERKEY :sekret2\r\n");
    try recvUntil(b, "PROP #p OWNERKEY :sekret2", 200);

    // C never enabled IRCX, so it received no PROP fanout at all.
    try std.testing.expect(std.mem.indexOf(u8, c.written(), "PROP #p") == null);
}

test "threaded server: PROP GET/LIST returns secret tier keys gated by rank (founder/owner/member), incl FOUNDERKEY + MEMBERKEY<->+k" {
    var server = Server.init(std.testing.allocator, .{ .host = "127.0.0.1", .port = 0 }) catch |err| switch (err) {
        error.Unsupported, error.PermissionDenied, error.SocketUnavailable => return error.SkipZigTest,
        else => return err,
    };
    defer server.deinit();
    const port = try server.boundPort();
    var run = std.atomic.Value(bool).init(true);
    var thr = try std.Thread.spawn(.{}, Server.runThreaded, .{ &server, &run });
    defer {
        run.store(false, .release);
        if (connectLoopback(port)) |wfd| closeFd(wfd) else |_| {}
        thr.join();
    }
    const fd_a = connectLoopback(port) catch return error.SkipZigTest;
    defer closeFd(fd_a);
    const fd_b = connectLoopback(port) catch return error.SkipZigTest;
    defer closeFd(fd_b);
    const alloc = std.testing.allocator;
    const a = try alloc.create(LiveClient);
    defer alloc.destroy(a);
    const b = try alloc.create(LiveClient);
    defer alloc.destroy(b);
    a.* = .{ .fd = fd_a };
    b.* = .{ .fd = fd_b };

    // A founds #k (founder, rank 4). B joins as a plain member (rank 0) BEFORE any
    // +k is set, so it stays a member once the join key exists.
    try writeAllFd(fd_a, "NICK A\r\nUSER alice 0 * :Alice\r\n");
    try recvUntil(a, " 001 A ", 200);
    try writeAllFd(fd_a, "IRCX\r\nJOIN #k\r\n");
    try recvUntil(a, " 366 A #k ", 200);
    try writeAllFd(fd_b, "NICK B\r\nUSER bob 0 * :Bob\r\n");
    try recvUntil(b, " 001 B ", 200);
    try writeAllFd(fd_b, "IRCX\r\nJOIN #k\r\n");
    try recvUntil(b, " 366 B #k ", 200);

    // Founder stores two secret tier keys and sets the live +k (==MEMBERKEY).
    try writeAllFd(fd_a, "PROP #k OWNERKEY :ownsek\r\nPROP #k FOUNDERKEY :fndsek\r\nMODE #k +k joinpass\r\n");
    try recvUntil(a, "MODE #k +k joinpass", 300);
    a.reset();

    // Founder GET each key: stored secrets read back RAW after the per-tier gate,
    // and MEMBERKEY resolves to the live +k value. (Reply numeric 818.)
    try writeAllFd(fd_a, "PROP #k OWNERKEY\r\nPROP #k FOUNDERKEY\r\nPROP #k MEMBERKEY\r\n");
    try recvUntil(a, "818 A #k OWNERKEY :ownsek", 300);
    try recvUntil(a, "818 A #k FOUNDERKEY :fndsek", 300);
    try recvUntil(a, "818 A #k MEMBERKEY :joinpass", 300);

    // Founder LIST (PROP #k) enumerates the now-visible secret tier keys.
    a.reset();
    try writeAllFd(fd_a, "PROP #k\r\n");
    try recvUntil(a, "819 A #k :End of properties", 300);
    try std.testing.expect(std.mem.indexOf(u8, a.written(), "OWNERKEY :ownsek") != null);
    try std.testing.expect(std.mem.indexOf(u8, a.written(), "FOUNDERKEY :fndsek") != null);

    // Plain member B: OWNERKEY/FOUNDERKEY are above its tier -> GET yields only the
    // 819 end with NO value line. MEMBERKEY is member-tier -> B reads the +k value
    // (matching MODE #k, which shows +k to members).
    b.reset();
    try writeAllFd(fd_b, "PROP #k OWNERKEY\r\n");
    try recvUntil(b, "819 B #k :End of properties", 300);
    try std.testing.expect(std.mem.indexOf(u8, b.written(), "OWNERKEY") == null);
    try std.testing.expect(std.mem.indexOf(u8, b.written(), "ownsek") == null);
    try std.testing.expect(std.mem.indexOf(u8, b.written(), "fndsek") == null);
    b.reset();
    try writeAllFd(fd_b, "PROP #k MEMBERKEY\r\n");
    try recvUntil(b, "818 B #k MEMBERKEY :joinpass", 300);
}

test "threaded server: JUPE command is oper-gated and manages the server-jupe list" {
    var server = Server.init(std.testing.allocator, operTestConfig(0)) catch |err| switch (err) {
        error.Unsupported, error.PermissionDenied, error.SocketUnavailable => return error.SkipZigTest,
        else => return err,
    };
    defer server.deinit();
    const port = try server.boundPort();
    var run = std.atomic.Value(bool).init(true);
    var thr = try std.Thread.spawn(.{}, Server.runThreaded, .{ &server, &run });
    defer {
        run.store(false, .release);
        if (connectLoopback(port)) |wfd| closeFd(wfd) else |_| {}
        thr.join();
    }
    const fd_o = connectLoopback(port) catch return error.SkipZigTest;
    defer closeFd(fd_o);
    const fd_b = connectLoopback(port) catch return error.SkipZigTest;
    defer closeFd(fd_b);
    var o = LiveClient{ .fd = fd_o };
    var b = LiveClient{ .fd = fd_b };

    try saslAdminPrelude(fd_o);
    try writeAllFd(fd_o, "NICK O\r\nUSER o 0 * :O\r\n");
    try recvUntil(&o, " 381 O ", 300); // elevated to oper
    try writeAllFd(fd_b, "NICK B\r\nUSER b 0 * :B\r\n");
    try recvUntil(&b, " 001 B ", 200);

    // A non-oper cannot JUPE (registry oper gate -> 481).
    try writeAllFd(fd_b, "JUPE evil.net 0 :nope\r\n");
    try recvUntil(&b, " 481 B ", 300);

    // Oper adds a jupe, lists it, then removes it.
    o.reset();
    try writeAllFd(fd_o, "JUPE evil.example.net 0 :rogue server\r\n");
    try recvUntil(&o, "JUPE added: evil.example.net", 300);
    o.reset();
    try writeAllFd(fd_o, "JUPE LIST\r\n");
    try recvUntil(&o, "JUPE evil.example.net", 300);
    try recvUntil(&o, "rogue server", 300);
    o.reset();
    try writeAllFd(fd_o, "UNJUPE evil.example.net\r\n");
    try recvUntil(&o, "JUPE removed", 300);

    // A malformed JUPE (missing duration + reason) is rejected with usage (461).
    o.reset();
    try writeAllFd(fd_o, "JUPE evil.example.net\r\n");
    try recvUntil(&o, " 461 O JUPE ", 300);
}

test "sanitizeKillReason strips control bytes and falls back to Killed" {
    var buf: [64]u8 = undefined;
    // Embedded control bytes (BEL, and a stray CR) are stripped; printable kept.
    try std.testing.expectEqualStrings("badreason", LinuxServer.sanitizeKillReason("bad\x07rea\rson", &buf));
    try std.testing.expectEqualStrings("flood abuse", LinuxServer.sanitizeKillReason("flood abuse", &buf));
    // An all-control (or empty) reason falls back to the default.
    try std.testing.expectEqualStrings("Killed", LinuxServer.sanitizeKillReason("\x01\x02\x03", &buf));
    try std.testing.expectEqualStrings("Killed", LinuxServer.sanitizeKillReason("", &buf));
}

