test "threaded server: AUDIT logs privileged actions (KILL, JUPE)" {
    var ident = try node_identity.fromSeed(@as([32]u8, @splat(0x9a)), "local");
    defer ident.deinit();
    var cfg = operTestConfig(0);
    cfg.node_id = ident.shortId();
    cfg.node_identity = &ident;
    var server = Server.init(std.testing.allocator, cfg) catch |err| switch (err) {
        error.Unsupported, error.PermissionDenied, error.SocketUnavailable => return error.SkipZigTest,
        else => return err,
    };
    defer server.deinit();
    const port = try server.boundPort();
    var run = std.atomic.Value(bool).init(true);
    var thr = try std.Thread.spawn(.{}, Server.runThreaded, .{ &server, &run });
    defer {
        run.store(false, .release);
        if (connectLoopback(port)) |wfd| closeFd(wfd) else |_| {}
        thr.join();
    }
    const fd_o = connectLoopback(port) catch return error.SkipZigTest;
    defer closeFd(fd_o);
    const fd_v = connectLoopback(port) catch return error.SkipZigTest;
    defer closeFd(fd_v);
    var o = LiveClient{ .fd = fd_o };
    var v = LiveClient{ .fd = fd_v };

    try saslAdminPrelude(fd_o);
    try writeAllFd(fd_o, "NICK O\r\nUSER o 0 * :O\r\n");
    try recvUntil(&o, " 381 O ", 300);
    o.reset();
    try writeAllFd(fd_o, "EVENT ADD KILL OPER_ACTION\r\n");
    try recvUntil(&o, "Event categories:", 300);
    try writeAllFd(fd_v, "NICK V\r\nUSER v 0 * :V\r\n");
    try recvUntil(&v, " 001 V ", 200);

    // Two privileged actions: a KILL and a JUPE.
    o.reset();
    try writeAllFd(fd_o, "KILL V :spam\r\n");
    try recvUntil(&v, "Killed", 300);
    try recvUntil(&o, "killed V ", 300);
    try std.testing.expect(std.mem.indexOf(u8, o.written(), "proof=") != null);
    o.reset();
    try writeAllFd(fd_o, "JUPE evil.example.net 0 :rogue\r\n");
    try recvUntil(&o, "JUPE added: evil.example.net", 300);
    try recvUntil(&o, "JUPE ADD evil.example.net proof=", 300);

    o.reset();
    try writeAllFd(fd_o, "SHUN bad!*@host.example 0 :quiet\r\n");
    try recvUntil(&o, "SHUN bad!*@host.example proof=", 300);

    o.reset();
    try writeAllFd(fd_o, "UNSHUN bad!*@host.example\r\n");
    try recvUntil(&o, "UNSHUN bad!*@host.example: removed proof=", 300);

    o.reset();
    try writeAllFd(fd_o, "WARD ADD host bad.example mesh expel 0 :bad ward\r\n");
    try recvUntil(&o, "WARD ADD host bad.example mesh/expel proof=", 300);

    o.reset();
    try writeAllFd(fd_o, "WARD DEL host bad.example\r\n");
    try recvUntil(&o, "WARD DEL host bad.example: removed proof=", 300);

    // AUDIT (newest first) shows the signed actions with actor/target/reason.
    o.reset();
    try writeAllFd(fd_o, "AUDIT\r\n");
    try recvUntil(&o, "O ward_del bad.example proof=", 300);
    try recvUntil(&o, "End of audit", 300);
    try std.testing.expect(std.mem.indexOf(u8, o.written(), "O ward_add bad.example proof=") != null);
    try std.testing.expect(std.mem.indexOf(u8, o.written(), "O unshun bad!*@host.example proof=") != null);
    try std.testing.expect(std.mem.indexOf(u8, o.written(), "O shun bad!*@host.example proof=") != null);
    try std.testing.expect(std.mem.indexOf(u8, o.written(), "O jupe evil.example.net proof=") != null);
    try std.testing.expect(std.mem.indexOf(u8, o.written(), "O kill V proof=") != null);

    const marker = "proof=";
    const proof_start = (std.mem.indexOf(u8, o.written(), marker) orelse return error.TestExpectedEqual) + marker.len;
    const proof_end = proof_start + proofmark.proof_id_hex_len;
    try std.testing.expect(proof_end <= o.written().len);
    var proof_id_buf: [proofmark.proof_id_hex_len]u8 = undefined;
    @memcpy(&proof_id_buf, o.written()[proof_start..proof_end]);
    const proof_id = proof_id_buf[0..];
    var proof_cmd_buf: [96]u8 = undefined;
    const proof_cmd = try std.fmt.bufPrint(&proof_cmd_buf, "AUDIT PROOF {s}\r\n", .{proof_id});
    o.reset();
    try writeAllFd(fd_o, proof_cmd);
    try recvUntil(&o, "valid=true", 300);
    try recvUntil(&o, "public_key=", 300);
    try std.testing.expect(std.mem.indexOf(u8, o.written(), "signature=") != null);
    try std.testing.expect(std.mem.indexOf(u8, o.written(), "EVENT O AUDIT") != null);

    o.reset();
    try writeAllFd(fd_o, "AUDIT JSON O 8\r\n");
    try recvUntil(&o, "\"type\":\"audit\"", 300);
    try recvUntil(&o, "\"type\":\"audit-entry\"", 300);
    try recvUntil(&o, "\"type\":\"audit-end\"", 300);
    try std.testing.expect(std.mem.indexOf(u8, o.written(), "EVENT O AUDIT") != null);
    try std.testing.expect(std.mem.indexOf(u8, o.written(), "\"proof_id\":") != null);
    try std.testing.expect(std.mem.indexOf(u8, o.written(), "\"action\":\"ward_del\"") != null);
    try std.testing.expect(std.mem.indexOf(u8, o.written(), "\"action\":\"ward_add\"") != null);
    try std.testing.expect(std.mem.indexOf(u8, o.written(), "\"action\":\"unshun\"") != null);
    try std.testing.expect(std.mem.indexOf(u8, o.written(), "\"action\":\"shun\"") != null);

    var proof_json_cmd_buf: [104]u8 = undefined;
    const proof_json_cmd = try std.fmt.bufPrint(&proof_json_cmd_buf, "AUDIT PROOF JSON {s}\r\n", .{proof_id});
    o.reset();
    try writeAllFd(fd_o, proof_json_cmd);
    try recvUntil(&o, "\"type\":\"audit-proof\"", 300);
    try recvUntil(&o, "\"valid\":true", 300);
    try recvUntil(&o, "\"public_key\":", 300);
    try std.testing.expect(std.mem.indexOf(u8, o.written(), "\"signature\":") != null);
    try std.testing.expect(std.mem.indexOf(u8, o.written(), "EVENT O AUDIT") != null);

    // Filtering by a different oper yields no entries.
    o.reset();
    try writeAllFd(fd_o, "AUDIT nobody\r\n");
    try recvUntil(&o, "End of audit (0)", 300);
    try std.testing.expect(std.mem.indexOf(u8, o.written(), "EVENT O AUDIT") != null);
}

test "threaded server: FORCE actions produce ProofMark audit events" {
