    try recvUntil(&o, " 381 O ", 300);
    try writeAllFd(fd_b, "NICK B\r\nUSER b 0 * :B\r\n");
    try recvUntil(&b, " 001 B ", 200);

    o.reset();
    try writeAllFd(fd_o, "FORCEJOIN #force B\r\n");
