        if (connectLoopback(port)) |wfd| closeFd(wfd) else |_| {}
        thr.join();
    }

    const fd = connectLoopback(port) catch return error.SkipZigTest;
    defer closeFd(fd);
    var client = LiveClient{ .fd = fd };
    try saslPlainPrelude(fd, "oper", "orochi");
    try writeAllFd(fd, "NICK O\r\nUSER oper 0 * :Limited Oper\r\n");
    try recvUntil(&client, " 001 O ", 200);
    try recvUntil(&client, " 381 O ", 200);

    // EVENT is an IRCX command — opt in (ISIRCX) first, else the opt-in gate
    // returns 421 before the event_subscribe privilege check can fire.
    try writeAllFd(fd, "IRCX\r\n");
    try recvUntil(&client, " 800 O ", 200);

    client.reset();
    try writeAllFd(fd, "EVENT LIST\r\n");
    try recvUntil(&client, " 481 O :Permission denied: requires the 'event_subscribe' operator privilege", 200);

    client.reset();
    try writeAllFd(fd, "EVENT OBSERVE *\r\n");
    try recvUntil(&client, " 481 O :Permission denied: requires the 'event_subscribe' operator privilege", 200);
}

test "threaded server: REDACT broadcast + WARD alias oper events" {
    var ident = try node_identity.fromSeed(@as([32]u8, @splat(0xb7)), "local");
    defer ident.deinit();
    var cfg = operTestConfig(0);
    cfg.node_identity = &ident;
    var server = Server.init(std.testing.allocator, cfg) catch |err| switch (err) {
        error.Unsupported, error.PermissionDenied, error.SocketUnavailable => return error.SkipZigTest,
        else => return err,
    };
    defer server.deinit();
    const port = try server.boundPort();
    var run = std.atomic.Value(bool).init(true);
    var thr = try std.Thread.spawn(.{}, Server.runThreaded, .{ &server, &run });
    defer {
        run.store(false, .release);
        if (connectLoopback(port)) |wfd| closeFd(wfd) else |_| {}
        thr.join();
    }
    const fd_a = connectLoopback(port) catch return error.SkipZigTest;
    defer closeFd(fd_a);
    var a = LiveClient{ .fd = fd_a };
    try saslPlainPreludeWithCaps(fd_a, "admin", "orochi", "draft/message-redaction standard-replies message-tags echo-message");
    try writeAllFd(fd_a, "NICK A\r\nUSER alice 0 * :Alice\r\n");
    try recvUntil(&a, " 001 A ", 200);
    try recvUntil(&a, " 381 A ", 200); // auto-elevated on SASL login
    try writeAllFd(fd_a, "JOIN #r\r\n");
    try recvUntil(&a, " 366 A #r ", 200);

    // REDACT broadcasts only for a real message id in the history ring.
    a.reset();
    try writeAllFd(fd_a, "PRIVMSG #r :before-redact\r\n");
    try recvUntil(&a, "PRIVMSG #r :before-redact", 200);
    const msgid = extractMsgid(a.written()) orelse return error.TestUnexpectedResult;
    var msgid_buf: [msgid_mod.id_len]u8 = undefined;
    try std.testing.expect(msgid.len <= msgid_buf.len);
    @memcpy(msgid_buf[0..msgid.len], msgid);
    const saved_msgid = msgid_buf[0..msgid.len];

    var redact_line: [256]u8 = undefined;
    const real_redact = std.fmt.bufPrint(&redact_line, "REDACT #r {s} :gone\r\n", .{saved_msgid}) catch unreachable;
    a.reset();
    try writeAllFd(fd_a, real_redact);
    try recvUntil(&a, "REDACT #r ", 200);
    try recvUntil(&a, " :gone", 200);
    try std.testing.expect(std.mem.indexOf(u8, a.written(), "proof=") != null);

    a.reset();
    try writeAllFd(fd_a, "AUDIT JSON A 5\r\n");
    try recvUntil(&a, "\"type\":\"audit-end\"", 300);
    try std.testing.expect(std.mem.indexOf(u8, a.written(), "\"action\":\"redact\"") != null);
    try std.testing.expect(std.mem.indexOf(u8, a.written(), "\"proof_id\":") != null);

    a.reset();
    try writeAllFd(fd_a, "REDACT #r bogus-msgid :gone\r\n");
    try recvUntil(&a, "FAIL REDACT UNKNOWN_MSGID", 200);

    // KLINE/DLINE/XLINE are WARD aliases and emit oper-action Event Spine notices.
    a.reset();
    try writeAllFd(fd_a, "KLINE bad!*@* :spam\r\n");
    try recvUntil(&a, " EVENT ", 200);
    a.reset();
    try writeAllFd(fd_a, "DLINE 203.0.113.0/24 :blocked\r\n");
    try recvUntil(&a, " EVENT ", 200);
    a.reset();
    try writeAllFd(fd_a, "XLINE BadReal* :bad realname\r\n");
    try recvUntil(&a, " EVENT ", 200);
    // TRACE -> 205 user line + 262 end.
    a.reset();
    try writeAllFd(fd_a, "TRACE\r\n");
    try recvUntil(&a, " 205 ", 200);
    try recvUntil(&a, " 262 ", 200);
    // TESTLINE: a host matching the KLINE bad!*@* reports RPL_TESTLINE 725;
    // a non-matching host reports RPL_NOTESTLINE 726.
    a.reset();
    try writeAllFd(fd_a, "TESTLINE bad!user@host\r\n");
    try recvUntil(&a, " 725 ", 200);
    a.reset();
    try writeAllFd(fd_a, "TESTLINE 203.0.113.12\r\n");
    try recvUntil(&a, " 725 ", 200);
    a.reset();
    try writeAllFd(fd_a, "WARD TEST realname BadRealName\r\n");
    try recvUntil(&a, "WARD TEST: matched realname BadReal* (expel) :bad realname", 200);
    a.reset();
    try writeAllFd(fd_a, "TESTLINE good!user@host\r\n");
    try recvUntil(&a, " 726 ", 200);
    // TESTMASK counts connected clients matching the mask (A itself matches).
    a.reset();
    try writeAllFd(fd_a, "TESTMASK *!*@localhost\r\n");
    try recvUntil(&a, " 727 ", 200);
}

test "threaded server: EDIT updates own message history and rejects others" {
    var server = Server.init(std.testing.allocator, .{ .host = "127.0.0.1", .port = 0 }) catch |err| switch (err) {
        error.Unsupported, error.PermissionDenied, error.SocketUnavailable => return error.SkipZigTest,
        else => return err,
    };
    defer server.deinit();
    const port = try server.boundPort();
    var run = std.atomic.Value(bool).init(true);
    var thr = try std.Thread.spawn(.{}, Server.runThreaded, .{ &server, &run });
    defer {
        run.store(false, .release);
        if (connectLoopback(port)) |wfd| closeFd(wfd) else |_| {}
        thr.join();
    }
    const fd_a = connectLoopback(port) catch return error.SkipZigTest;
    defer closeFd(fd_a);
    const fd_b = connectLoopback(port) catch return error.SkipZigTest;
    defer closeFd(fd_b);
    var a = LiveClient{ .fd = fd_a };
    var b = LiveClient{ .fd = fd_b };

    try writeAllFd(fd_a, "CAP LS 302\r\n");
    try recvUntil(&a, "draft/message-editing", 200);
    a.reset();
    try writeAllFd(fd_a, "CAP REQ :message-tags echo-message draft/chathistory draft/message-editing\r\nNICK A\r\nUSER alice 0 * :Alice\r\nCAP END\r\n");
    try recvUntil(&a, " 001 A ", 200);
    try writeAllFd(fd_b, "CAP REQ :draft/message-editing standard-replies\r\nNICK B\r\nUSER bob 0 * :Bob\r\nCAP END\r\n");
    try recvUntil(&b, " 001 B ", 200);
    try writeAllFd(fd_a, "JOIN #edit\r\n");
    try recvUntil(&a, " 366 A #edit ", 200);
    try writeAllFd(fd_b, "JOIN #edit\r\n");
    try recvUntil(&b, " 366 B #edit ", 200);

    a.reset();
    try writeAllFd(fd_a, "PRIVMSG #edit :before\r\n");
    try recvUntil(&a, "PRIVMSG #edit :before", 200);
    const msgid = extractMsgid(a.written()) orelse return error.TestUnexpectedResult;
    var msgid_buf: [msgid_mod.id_len]u8 = undefined;
    try std.testing.expect(msgid.len <= msgid_buf.len);
    @memcpy(msgid_buf[0..msgid.len], msgid);
    const saved_msgid = msgid_buf[0..msgid.len];

    var edit_line: [256]u8 = undefined;
    const own_edit = std.fmt.bufPrint(&edit_line, "EDIT #edit {s} :after\r\n", .{saved_msgid}) catch unreachable;
    a.reset();
    try writeAllFd(fd_a, own_edit);
    try recvUntil(&a, "+draft/edit=", 200);
    try recvUntil(&a, "PRIVMSG #edit :after", 200);

    b.reset();
    const bad_edit = std.fmt.bufPrint(&edit_line, "EDIT #edit {s} :hijack\r\n", .{saved_msgid}) catch unreachable;
    try writeAllFd(fd_b, bad_edit);
    try recvUntil(&b, "FAIL EDIT PERMISSION_DENIED", 200);

    a.reset();
    try writeAllFd(fd_a, "CHATHISTORY LATEST #edit * 10\r\n");
    try recvUntil(&a, "PRIVMSG #edit :after", 200);
    try std.testing.expect(std.mem.indexOf(u8, a.written(), "PRIVMSG #edit :before") == null);
}

test "threaded server: EDIT and REDACT notify only matching draft-cap recipients" {
    var server = Server.init(std.testing.allocator, .{ .host = "127.0.0.1", .port = 0 }) catch |err| switch (err) {
        error.Unsupported, error.PermissionDenied, error.SocketUnavailable => return error.SkipZigTest,
        else => return err,
    };
    defer server.deinit();
    const port = try server.boundPort();
    var run = std.atomic.Value(bool).init(true);
    var thr = try std.Thread.spawn(.{}, Server.runThreaded, .{ &server, &run });
    defer {
        run.store(false, .release);
        if (connectLoopback(port)) |wfd| closeFd(wfd) else |_| {}
        thr.join();
    }
    const fd_a = connectLoopback(port) catch return error.SkipZigTest;
    defer closeFd(fd_a);
    const fd_b = connectLoopback(port) catch return error.SkipZigTest;
    defer closeFd(fd_b);
    const fd_c = connectLoopback(port) catch return error.SkipZigTest;
    defer closeFd(fd_c);
    var a = LiveClient{ .fd = fd_a };
    var b = LiveClient{ .fd = fd_b };
    var c = LiveClient{ .fd = fd_c };

    try writeAllFd(fd_a, "CAP REQ :message-tags echo-message draft/message-editing draft/message-redaction standard-replies\r\nNICK A\r\nUSER alice 0 * :Alice\r\nCAP END\r\n");
    try recvUntil(&a, " 001 A ", 200);
    try writeAllFd(fd_b, "NICK B\r\nUSER bob 0 * :Bob\r\n");
    try recvUntil(&b, " 001 B ", 200);
    try writeAllFd(fd_c, "CAP REQ :server-time draft/message-editing draft/message-redaction\r\nNICK C\r\nUSER carol 0 * :Carol\r\nCAP END\r\n");
    try recvUntil(&c, " 001 C ", 200);

    try writeAllFd(fd_a, "JOIN #draftcap\r\n");
    try recvUntil(&a, " 366 A #draftcap ", 200);
    try writeAllFd(fd_b, "JOIN #draftcap\r\n");
    try recvUntil(&b, " 366 B #draftcap ", 200);
    try writeAllFd(fd_c, "JOIN #draftcap\r\n");
    try recvUntil(&c, " 366 C #draftcap ", 200);

    a.reset();
    b.reset();
    c.reset();
    try writeAllFd(fd_a, "PRIVMSG #draftcap :before-edit\r\n");
    try recvUntil(&a, "PRIVMSG #draftcap :before-edit", 200);
    const edit_msgid = extractMsgid(a.written()) orelse return error.TestUnexpectedResult;
    var edit_msgid_buf: [msgid_mod.id_len]u8 = undefined;
    @memcpy(edit_msgid_buf[0..edit_msgid.len], edit_msgid);
    const saved_edit_msgid = edit_msgid_buf[0..edit_msgid.len];

    var edit_line: [256]u8 = undefined;
    const own_edit = std.fmt.bufPrint(&edit_line, "EDIT #draftcap {s} :after-edit\r\n", .{saved_edit_msgid}) catch unreachable;
    b.reset();
    c.reset();
    try writeAllFd(fd_a, own_edit);
    try recvUntil(&c, "PRIVMSG #draftcap :after-edit", 200);
    try std.testing.expect(std.mem.indexOf(u8, c.written(), " @msgid=") == null);
    try std.testing.expect(std.mem.indexOf(u8, c.written(), "+draft/edit=") != null);
    waitMillis(50);
    try b.readAvailable();
    try std.testing.expect(std.mem.indexOf(u8, b.written(), "after-edit") == null);

    a.reset();
    b.reset();
    c.reset();
    try writeAllFd(fd_a, "PRIVMSG #draftcap :before-redact\r\n");
    try recvUntil(&a, "PRIVMSG #draftcap :before-redact", 200);
    const redact_msgid = extractMsgid(a.written()) orelse return error.TestUnexpectedResult;
    var redact_msgid_buf: [msgid_mod.id_len]u8 = undefined;
    @memcpy(redact_msgid_buf[0..redact_msgid.len], redact_msgid);
    const saved_redact_msgid = redact_msgid_buf[0..redact_msgid.len];

    var redact_line: [256]u8 = undefined;
    const redact = std.fmt.bufPrint(&redact_line, "REDACT #draftcap {s} :gone\r\n", .{saved_redact_msgid}) catch unreachable;
    b.reset();
    c.reset();
    try writeAllFd(fd_a, redact);
    try recvUntil(&c, "REDACT #draftcap ", 200);
    waitMillis(50);
    try b.readAvailable();
    try std.testing.expect(std.mem.indexOf(u8, b.written(), "REDACT #draftcap") == null);
}

