    try writeAllFd(fd_a, "NICK A\r\nUSER alice 0 * :Alice\r\n");
    try writeAllFd(fd_b, "NICK B\r\nUSER bob 0 * :Bob\r\n");
    try recvUntil(&a, " 001 A ", 200);
    try recvUntil(&b, " 001 B ", 200);

    try writeAllFd(fd_a, "JOIN #n\r\n");
    try recvUntil(&a, " 366 A #n ", 200);
    try writeAllFd(fd_b, "JOIN #n\r\n");
    try recvUntil(&b, " 366 B #n ", 200);

    // A changes nick -> B (common channel) and A both see the NICK line.
    a.reset();
    b.reset();
    try writeAllFd(fd_a, "NICK Alice2\r\n");
    try recvUntil(&b, ":A!alice@localhost NICK :Alice2\r\n", 200);
    try recvUntil(&a, "NICK :Alice2\r\n", 200);

    // B cannot take the now-occupied nick -> 433.
    b.reset();
    try writeAllFd(fd_b, "NICK Alice2\r\n");
    try recvUntil(&b, " 433 ", 200);
}

test "threaded server: IRCv3 extended-join per-recipient format" {
    var server = Server.init(std.testing.allocator, .{ .host = "127.0.0.1", .port = 0 }) catch |err| switch (err) {
        error.Unsupported, error.PermissionDenied, error.SocketUnavailable => return error.SkipZigTest,
        else => return err,
    };
    defer server.deinit();
    const port = try server.boundPort();

    var run = std.atomic.Value(bool).init(true);
    var thr = try std.Thread.spawn(.{}, Server.runThreaded, .{ &server, &run });
    defer {
        run.store(false, .release);
        if (connectLoopback(port)) |wfd| closeFd(wfd) else |_| {}
        thr.join();
    }

    const fd_a = connectLoopback(port) catch return error.SkipZigTest;
    defer closeFd(fd_a);
    const fd_b = connectLoopback(port) catch return error.SkipZigTest;
    defer closeFd(fd_b);
    var a = LiveClient{ .fd = fd_a };
    var b = LiveClient{ .fd = fd_b };

    try writeAllFd(fd_a, "CAP REQ :extended-join\r\n");
    try recvUntil(&a, "ACK :extended-join", 200);
    try writeAllFd(fd_a, "NICK A\r\nUSER alice 0 * :Alice\r\nCAP END\r\n");
    try recvUntil(&a, " 001 A ", 200);
    try writeAllFd(fd_b, "NICK B\r\nUSER bob 0 * :Bob\r\n");
    try recvUntil(&b, " 001 B ", 200);

    try writeAllFd(fd_a, "JOIN #e\r\n");
    try recvUntil(&a, " 366 A #e ", 200);

    // B joins; A (extended-join) sees the account + realname form (account "*"
    // since B isn't logged in).
    a.reset();
    try writeAllFd(fd_b, "JOIN #e\r\n");
    try recvUntil(&a, ":B!bob@localhost JOIN #e * :Bob\r\n", 200);
}

test "GRANT privilege resolution: class presets, explicit list, tombstone" {
    const P = oper_mod.Privilege;
    // admin/netadmin/sa => full authority (carries oper_grant).
    try std.testing.expect(LinuxServer.grantPrivileges("admin", "").?.has(.oper_grant));
    try std.testing.expect(LinuxServer.grantPrivileges("netadmin", "").?.has(.server_admin));
    // A plain class is an operator but NOT a grantor.
    const op = LinuxServer.grantPrivileges("oper", "").?;
    try std.testing.expect(op.has(.client_kill));
    try std.testing.expect(!op.has(.oper_grant));
    // An explicit privilege list takes exactly those privileges.
    const custom = LinuxServer.grantPrivileges("x", "client_kill, oper_spy").?;
    try std.testing.expect(custom.has(.client_kill) and custom.has(.oper_spy));
    try std.testing.expect(!custom.has(.server_rehash));
    try std.testing.expect(LinuxServer.grantPrivileges("x", "not_a_privilege") == null);
    // The revocation tombstone is the unique privilege_bits == 0 grant.
    try std.testing.expectEqual(@as(u64, 0), oper_mod.OperPrivileges.empty.toBits());
    try std.testing.expect(LinuxServer.grantPrivileges("admin", "").?.toBits() != 0);
    _ = P;
}

test "threaded server: MONITOR online/offline/list end-to-end" {
    var server = Server.init(std.testing.allocator, .{ .host = "127.0.0.1", .port = 0, .monitorlimit = 1 }) catch |err| switch (err) {
        error.Unsupported, error.PermissionDenied, error.SocketUnavailable => return error.SkipZigTest,
        else => return err,
    };
    defer server.deinit();
    const port = try server.boundPort();

    var run = std.atomic.Value(bool).init(true);
    var thr = try std.Thread.spawn(.{}, Server.runThreaded, .{ &server, &run });
    defer {
        run.store(false, .release);
        if (connectLoopback(port)) |wfd| closeFd(wfd) else |_| {}
        thr.join();
    }

    const fd_a = connectLoopback(port) catch return error.SkipZigTest;
    defer closeFd(fd_a);
    var a = LiveClient{ .fd = fd_a };
    try writeAllFd(fd_a, "NICK A\r\nUSER alice 0 * :Alice\r\n");
    try recvUntil(&a, " 001 A ", 200);

    // A monitors B while B is offline -> RPL_MONOFFLINE (731).
    a.reset();
    try writeAllFd(fd_a, "MONITOR + B\r\n");
    try recvUntil(&a, " 731 A :B", 200);

    // B connects and registers -> A is told B is online (730).
    a.reset();
    const fd_b = connectLoopback(port) catch return error.SkipZigTest;
    var b = LiveClient{ .fd = fd_b };
    try writeAllFd(fd_b, "NICK B\r\nUSER bob 0 * :Bob\r\n");
    try recvUntil(&b, " 001 B ", 200);
    try recvUntil(&a, " 730 A :B!bob@localhost", 200);

    a.reset();
    try writeAllFd(fd_a, "MONITOR + C\r\n");
    try recvUntil(&a, " 734 A 1 C :Monitor list is full", 200);

    // MONITOR L -> 732 list + 733 end.
    a.reset();
    try writeAllFd(fd_a, "MONITOR L\r\n");
    try recvUntil(&a, " 732 A :B", 200);
    try recvUntil(&a, " 733 A ", 200);

    // B quits -> A is told B is offline (731).
    a.reset();
    try writeAllFd(fd_b, "QUIT :bye\r\n");
    try recvUntil(&a, " 731 A :B", 200);
    closeFd(fd_b);
}

